{
  "name": "Narrador Pro - Football Dashboard",
  "description": "A high-performance assistant for football narrators with tactical field views, AI-powered team setup (OCR/Voice), real-time stats, and intelligent match event tracking.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

export type Position = 'GK' | 'DF' | 'MF' | 'FW';

export interface Player {
  id: string;
  name: string;
  fullName: string;
  number: number;
  position: Position;
  teamId: 'home' | 'away';
  isStarter: boolean;
  events: MatchEvent[];
}

export interface Team {
  id: 'home' | 'away';
  name: string;
  color: string;
  players: Player[];
}

export type EventType = 'GOAL' | 'YELLOW_CARD' | 'RED_CARD' | 'SUBSTITUTION' | 'SHOT' | 'FOUL' | 'CORNER';

export interface MatchEvent {
  id: string;
  type: EventType;
  minute: number;
  playerId?: string;
  relatedPlayerId?: string; // e.g., assistant or sub-in
  teamId: 'home' | 'away';
  description: string;
  timestamp: number;
}

export interface MatchState {
  homeTeam: Team;
  awayTeam: Team;
  events: MatchEvent[];
  startTime: number | null;
  currentTime: number; // match minute
  isPaused: boolean;
}

export interface AICommandResponse {
  type: EventType | 'INVALID';
  team?: 'home' | 'away';
  playerNumber?: number;
  playerInNumber?: number;
  playerOutNumber?: number;
  description: string;
}

import { Team } from './types';

export const DEFAULT_HOME_TEAM: Team = {
  id: 'home',
  name: 'Time Casa',
  color: '#3b82f6',
  players: [],
};

export const DEFAULT_AWAY_TEAM: Team = {
  id: 'away',
  name: 'Time Visitante',
  color: '#ef4444',
  players: [],
};

export const STORAGE_KEY = 'narrador_pro_match_data';

import { GoogleGenAI, Type } from "@google/genai";
import { AICommandResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const parsePlayersFromImage = async (base64Image: string): Promise<any> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image,
          },
        },
        {
          text: `Extract the football player list from this image. 
          Return a JSON array of objects with 'name' (full name) and 'number' (integer). 
          Determine which team they belong to if possible (teamA or teamB).`
        }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          teamA: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                number: { type: Type.NUMBER }
              }
            }
          },
          teamB: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                number: { type: Type.NUMBER }
              }
            }
          }
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const processVoiceCommand = async (command: string, context: string): Promise<AICommandResponse> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze this match narration command: "${command}". 
    Context: ${context}.
    Identify the event type (GOAL, YELLOW_CARD, RED_CARD, SUBSTITUTION, SHOT, FOUL, CORNER), the team ('home' or 'away'), and player numbers involved.
    Return JSON.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          type: { type: Type.STRING },
          team: { type: Type.STRING },
          playerNumber: { type: Type.NUMBER },
          playerInNumber: { type: Type.NUMBER },
          playerOutNumber: { type: Type.NUMBER },
          description: { type: Type.STRING }
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateMatchReport = async (events: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Based on these match events: ${events}, write a professional, engaging summary report of the football match as a narrator would describe the final results and highlights. Use Markdown.`
  });
  return response.text || "Report generation failed.";
};

import React from 'react';
import { Team, Player } from '../types';

interface FieldProps {
  homeTeam: Team;
  awayTeam: Team;
  onPlayerClick: (player: Player) => void;
}

const Field: React.FC<FieldProps> = ({ homeTeam, awayTeam, onPlayerClick }) => {
  // Simple layout logic for 4-4-2 default visualization
  const getPositionStyles = (index: number, teamId: 'home' | 'away') => {
    const isHome = teamId === 'home';
    const baseRows = [
      { top: '50%', left: isHome ? '8%' : '92%' }, // GK
      { top: '20%', left: isHome ? '25%' : '75%' }, { top: '40%', left: isHome ? '25%' : '75%' }, 
      { top: '60%', left: isHome ? '25%' : '75%' }, { top: '80%', left: isHome ? '25%' : '75%' }, // DF
      { top: '20%', left: isHome ? '45%' : '55%' }, { top: '40%', left: isHome ? '45%' : '55%' },
      { top: '60%', left: isHome ? '45%' : '55%' }, { top: '80%', left: isHome ? '45%' : '55%' }, // MF
      { top: '35%', left: isHome ? '65%' : '35%' }, { top: '65%', left: isHome ? '65%' : '35%' }, // FW
    ];
    return baseRows[index] || { top: '50%', left: '50%' };
  };

  const renderPlayers = (team: Team) => {
    return team.players.filter(p => p.isStarter).slice(0, 11).map((player, idx) => {
      const pos = getPositionStyles(idx, team.id);
      return (
        <button
          key={player.id}
          onClick={() => onPlayerClick(player)}
          className="absolute -translate-x-1/2 -translate-y-1/2 group transition-transform hover:scale-110"
          style={{ top: pos.top, left: pos.left }}
        >
          <div 
            className="w-10 h-10 md:w-12 md:h-12 rounded-full flex items-center justify-center border-2 border-white shadow-xl text-white font-bold text-sm md:text-base"
            style={{ backgroundColor: team.color }}
          >
            {player.number}
          </div>
          <div className="mt-1 bg-black/80 text-white px-2 py-0.5 rounded text-[10px] md:text-xs font-semibold whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity">
            {player.name}
          </div>
        </button>
      );
    });
  };

  return (
    <div className="relative w-full aspect-[4/3] bg-emerald-700 rounded-xl overflow-hidden shadow-2xl border-4 border-emerald-800">
      {/* Field markings */}
      <div className="absolute inset-0 border-2 border-white/30 m-4"></div>
      <div className="absolute inset-y-0 left-1/2 w-0.5 bg-white/30"></div>
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-32 h-32 border-2 border-white/30 rounded-full"></div>

      {/* Penalty areas */}
      <div className="absolute top-1/2 left-0 -translate-y-1/2 w-24 h-48 border-2 border-white/30 border-l-0"></div>
      <div className="absolute top-1/2 right-0 -translate-y-1/2 w-24 h-48 border-2 border-white/30 border-r-0"></div>

      {renderPlayers(homeTeam)}
      {renderPlayers(awayTeam)}
    </div>
  );
};

export default Field;

import React from 'react';
import { Team, Player } from '../types';
import { Shield, User, Star } from 'lucide-react';

interface PlayerListProps {
  team: Team;
  onPlayerClick?: (player: Player) => void;
}

const PlayerList: React.FC<PlayerListProps> = ({ team, onPlayerClick }) => {
  return (
    <div className="flex flex-col gap-2">
      <div className="flex items-center gap-2 px-3 py-2 bg-slate-800 rounded-t-lg border-b border-slate-700">
        <Shield className="w-5 h-5" style={{ color: team.color }} />
        <h3 className="font-bold text-lg">{team.name}</h3>
      </div>
      <div className="max-h-[500px] overflow-y-auto space-y-1 pr-1">
        {team.players.length === 0 ? (
          <p className="text-slate-500 text-sm italic p-4 text-center">Nenhum jogador cadastrado</p>
        ) : (
          team.players.sort((a, b) => (a.isStarter === b.isStarter ? 0 : a.isStarter ? -1 : 1)).map(player => (
