              <div className="flex items-center gap-3">
                <span className="w-6 font-mono font-bold text-slate-400">#{player.number}</span>
                <div>
                  <div className="flex items-center gap-1 font-semibold text-sm">
                    {player.name}
                    {player.isStarter && <Star className="w-3 h-3 text-yellow-500 fill-yellow-500" />}
                  </div>
                  <div className="text-[10px] text-slate-500 uppercase">{player.position}</div>
                </div>
              </div>
              <div className="flex gap-1">
                {player.events.map(ev => (
                  <span key={ev.id} className="w-2 h-2 rounded-full" title={ev.type} style={{
                    backgroundColor: ev.type === 'GOAL' ? '#fbbf24' : ev.type === 'YELLOW_CARD' ? '#fde047' : ev.type === 'RED_CARD' ? '#ef4444' : '#94a3b8'
                  }} />
                ))}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default PlayerList;

import React from 'react';
import { MatchState, MatchEvent } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { Trophy, Clock, Target, AlertTriangle } from 'lucide-react';

interface MatchStatsProps {
  state: MatchState;
}

const MatchStats: React.FC<MatchStatsProps> = ({ state }) => {
  const getTeamStats = (teamId: 'home' | 'away') => {
    const events = state.events.filter(e => e.teamId === teamId);
    return {
      goals: events.filter(e => e.type === 'GOAL').length,
      yellowCards: events.filter(e => e.type === 'YELLOW_CARD').length,
      redCards: events.filter(e => e.type === 'RED_CARD').length,
      shots: events.filter(e => e.type === 'SHOT').length,
      fouls: events.filter(e => e.type === 'FOUL').length,
      corners: events.filter(e => e.type === 'CORNER').length,
    };
  };

  const homeStats = getTeamStats('home');
  const awayStats = getTeamStats('away');

  const chartData = [
    { name: 'Gols', home: homeStats.goals, away: awayStats.goals },
    { name: 'Chutes', home: homeStats.shots, away: awayStats.shots },
    { name: 'Faltas', home: homeStats.fouls, away: awayStats.fouls },
    { name: 'Amarelos', home: homeStats.yellowCards, away: awayStats.yellowCards },
  ];

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 p-6 bg-slate-900">
      {/* Quick Overview */}
      <div className="col-span-full bg-slate-800 p-6 rounded-2xl shadow-lg border border-slate-700">
        <div className="flex justify-between items-center">
          <div className="text-center flex-1">
            <h2 className="text-2xl font-black mb-1">{state.homeTeam.name}</h2>
            <div className="text-6xl font-black" style={{ color: state.homeTeam.color }}>{homeStats.goals}</div>
          </div>
          <div className="px-6 text-center">
            <div className="text-slate-500 font-bold mb-2">VS</div>
            <div className="bg-slate-700 px-3 py-1 rounded-full text-sm font-mono flex items-center gap-2">
              <Clock className="w-4 h-4" /> {state.currentTime}'
            </div>
          </div>
          <div className="text-center flex-1">
            <h2 className="text-2xl font-black mb-1">{state.awayTeam.name}</h2>
            <div className="text-6xl font-black" style={{ color: state.awayTeam.color }}>{awayStats.goals}</div>
          </div>
        </div>
      </div>

      {/* Comparison Chart */}
      <div className="col-span-1 md:col-span-2 bg-slate-800 p-6 rounded-2xl border border-slate-700 min-h-[300px]">
        <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
          <Target className="w-5 h-5 text-blue-400" /> Comparativo de Jogo
        </h3>
        <ResponsiveContainer width="100%" height={240}>
          <BarChart data={chartData} layout="vertical">
            <CartesianGrid strokeDasharray="3 3" stroke="#334155" horizontal={false} />
            <XAxis type="number" hide />
            <YAxis dataKey="name" type="category" stroke="#94a3b8" />
            <Tooltip 
              contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px' }}
              itemStyle={{ color: '#fff' }}
            />
            <Bar dataKey="home" fill={state.homeTeam.color} radius={[0, 4, 4, 0]} />
            <Bar dataKey="away" fill={state.awayTeam.color} radius={[0, 4, 4, 0]} />
          </BarChart>
        </ResponsiveContainer>
      </div>

      {/* Cards & Fouls Info */}
      <div className="bg-slate-800 p-6 rounded-2xl border border-slate-700">
        <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
          <AlertTriangle className="w-5 h-5 text-yellow-500" /> Disciplina
        </h3>
        <div className="space-y-4">
          <div className="flex justify-between items-center text-sm">
            <span className="text-slate-400">Cartões Amarelos</span>
            <div className="flex gap-4 font-bold">
              <span style={{ color: state.homeTeam.color }}>{homeStats.yellowCards}</span>
              <span style={{ color: state.awayTeam.color }}>{awayStats.yellowCards}</span>
            </div>
          </div>
          <div className="flex justify-between items-center text-sm">
            <span className="text-slate-400">Cartões Vermelhos</span>
            <div className="flex gap-4 font-bold">
              <span style={{ color: state.homeTeam.color }}>{homeStats.redCards}</span>
              <span style={{ color: state.awayTeam.color }}>{awayStats.redCards}</span>
            </div>
          </div>
          <div className="flex justify-between items-center text-sm">
            <span className="text-slate-400">Escanteios</span>
            <div className="flex gap-4 font-bold">
              <span style={{ color: state.homeTeam.color }}>{homeStats.corners}</span>
              <span style={{ color: state.awayTeam.color }}>{awayStats.corners}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MatchStats;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  LayoutGrid, 
  List, 
  Mic, 
  Camera, 
  Settings, 
  History, 
  Save, 
  RotateCcw, 
  Play, 
  Pause,
  MessageSquare,
  FileText,
  BarChart2,
  Trophy,
  ArrowRightLeft,
  Search
} from 'lucide-react';
import { 
  MatchState, 
  Player, 
  Team, 
  MatchEvent, 
  EventType, 
  Position 
} from './types';
import { 
  DEFAULT_HOME_TEAM, 
  DEFAULT_AWAY_TEAM, 
  STORAGE_KEY 
} from './constants';
import Field from './components/Field';
import PlayerList from './components/PlayerList';
import MatchStats from './components/MatchStats';
import { parsePlayersFromImage, processVoiceCommand, generateMatchReport } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'main' | 'stats' | 'report'>('main');
  const [viewMode, setViewMode] = useState<'field' | 'list'>('field');
  const [matchState, setMatchState] = useState<MatchState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : {
      homeTeam: DEFAULT_HOME_TEAM,
      awayTeam: DEFAULT_AWAY_TEAM,
      events: [],
      startTime: null,
      currentTime: 0,
      isPaused: true,
    };
  });

  const [history, setHistory] = useState<MatchState[]>([]);
  const [isRecording, setIsRecording] = useState(false);
  const [commandText, setCommandText] = useState('');
  const [finalReport, setFinalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [showUndoConfirm, setShowUndoConfirm] = useState(false);

  // Auto-save logic
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(matchState));
  }, [matchState]);

  // Match clock logic
  useEffect(() => {
    let interval: any;
    if (!matchState.isPaused && matchState.startTime) {
      interval = setInterval(() => {
        setMatchState(prev => ({
          ...prev,
          currentTime: prev.currentTime + 1
        }));
      }, 60000); // Increment every minute
    }
    return () => clearInterval(interval);
  }, [matchState.isPaused, matchState.startTime]);

  const saveToHistory = useCallback(() => {
    setHistory(prev => [...prev.slice(-10), JSON.parse(JSON.stringify(matchState))]);
  }, [matchState]);

  const addEvent = (eventData: Omit<MatchEvent, 'id' | 'timestamp' | 'minute'>) => {
    saveToHistory();
    const newEvent: MatchEvent = {
      ...eventData,
      id: Math.random().toString(36).substr(2, 9),
      minute: matchState.currentTime,
      timestamp: Date.now(),
    };

    setMatchState(prev => {
      // Update player event lists
      const updateTeam = (team: Team) => ({
        ...team,
        players: team.players.map(p => 
          p.id === newEvent.playerId || p.id === newEvent.relatedPlayerId
          ? { ...p, events: [...p.events, newEvent] }
          : p
        )
      });

      return {
        ...prev,
        events: [newEvent, ...prev.events],
        homeTeam: updateTeam(prev.homeTeam),
        awayTeam: updateTeam(prev.awayTeam),
      };
    });
  };

  const handleUndo = () => {
    if (history.length > 0) {
      setMatchState(history[history.length - 1]);
      setHistory(prev => prev.slice(0, -1));
      setShowUndoConfirm(false);
    }
  };

  const handleCommand = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!commandText.trim()) return;

    try {
      const result = await processVoiceCommand(commandText, `Match minute ${matchState.currentTime}. Home: ${matchState.homeTeam.name}, Away: ${matchState.awayTeam.name}`);

      if (result.type !== 'INVALID') {
        const team = result.team === 'home' ? matchState.homeTeam : matchState.awayTeam;
        const player = team.players.find(p => p.number === result.playerNumber);

        addEvent({
          type: result.type as EventType,
          teamId: result.team as 'home' | 'away',
          playerId: player?.id,
          description: result.description
        });
        setCommandText('');
      } else {
        alert("Comando não reconhecido. Tente algo como: 'Gol do número 10 do time casa'");
      }
    } catch (error) {
      console.error(error);
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result?.toString().split(',')[1];
      if (base64) {
        try {
          const data = await parsePlayersFromImage(base64);

          const createPlayers = (list: any[], teamId: 'home' | 'away') => {
            return list.map((p: any, i: number) => {
              const names = p.name.split(' ');
              const shortName = names.length > 1 ? names[0] : p.name;
              return {
                id: Math.random().toString(36).substr(2, 9),
                fullName: p.name,
                name: shortName,
                number: p.number,
                teamId,
                isStarter: i < 11,
                position: (i === 0 ? 'GK' : i < 5 ? 'DF' : i < 9 ? 'MF' : 'FW') as Position,
                events: []
              };
            });
          };

          setMatchState(prev => ({
            ...prev,
            homeTeam: { ...prev.homeTeam, players: createPlayers(data.teamA || [], 'home') },
            awayTeam: { ...prev.awayTeam, players: createPlayers(data.teamB || [], 'away') }
          }));
        } catch (error) {
          alert("Erro ao processar imagem.");
        }
      }
    };
    reader.readAsDataURL(file);
  };

  const createReport = async () => {
    setIsGeneratingReport(true);
    const eventLog = matchState.events.map(e => `${e.minute}': ${e.description}`).join('\n');
    const report = await generateMatchReport(eventLog);
    setFinalReport(report);
    setActiveTab('report');
    setIsGeneratingReport(false);
  };

  const handleVoiceInput = () => {
    // Simple mock since real continuous transcription requires complex setup
    // but we can simulate the UI state
    setIsRecording(!isRecording);
    if (!isRecording) {
      // Logic for Web Speech API could go here
    }
  };

  return (
    <div className="min-h-screen flex flex-col max-w-6xl mx-auto p-4 md:p-6 pb-24">
      {/* Header */}
      <header className="flex justify-between items-center mb-8 bg-slate-800/50 p-4 rounded-2xl border border-slate-700 backdrop-blur-md">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-blue-600 rounded-xl">
            <Trophy className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-black uppercase tracking-tighter">Narrador Pro</h1>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Match Assistant AI</p>
          </div>
        </div>

        <div className="flex gap-2">
          <button 
            onClick={() => setMatchState(p => ({ ...p, isPaused: !p.isPaused, startTime: p.startTime || Date.now() }))}
            className={`flex items-center gap-2 px-4 py-2 rounded-xl font-bold transition-all ${
              matchState.isPaused ? 'bg-emerald-600 hover:bg-emerald-500' : 'bg-red-600 hover:bg-red-500'
            }`}
          >
            {matchState.isPaused ? <Play size={18} /> : <Pause size={18} />}
            {matchState.currentTime}'
          </button>
          <button onClick={() => setShowUndoConfirm(true)} className="p-2 bg-slate-700 hover:bg-slate-600 rounded-xl transition-colors">
            <RotateCcw size={20} />
          </button>
        </div>
      </header>

      {/* Main Tabs */}
      <nav className="flex gap-2 mb-6 bg-slate-900/50 p-1.5 rounded-2xl border border-slate-700 self-center">
        <button 
          onClick={() => setActiveTab('main')}
          className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all ${activeTab === 'main' ? 'bg-slate-700 text-white' : 'text-slate-400 hover:text-white'}`}
        >
          <LayoutGrid size={18} /> Campo
        </button>
        <button 
          onClick={() => setActiveTab('stats')}
          className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all ${activeTab === 'stats' ? 'bg-slate-700 text-white' : 'text-slate-400 hover:text-white'}`}
        >
          <BarChart2 size={18} /> Estatísticas
        </button>
        <button 
          onClick={() => setActiveTab('report')}
          className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all ${activeTab === 'report' ? 'bg-slate-700 text-white' : 'text-slate-400 hover:text-white'}`}
        >
          <FileText size={18} /> Relatório
        </button>
      </nav>

      {/* Content Area */}
      <main className="flex-1 mb-8 overflow-hidden rounded-3xl">
        {activeTab === 'main' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full">
            {/* Left Sidebar - Home Team */}
            <div className="lg:col-span-3 bg-slate-800/30 p-4 rounded-3xl border border-slate-700/50 flex flex-col gap-4">
