              ) : (
                <div className="grid grid-cols-2 gap-4 h-full">
                   <div className="bg-slate-800/40 p-4 rounded-2xl"><PlayerList team={matchState.homeTeam} /></div>
                   <div className="bg-slate-800/40 p-4 rounded-2xl"><PlayerList team={matchState.awayTeam} /></div>
                </div>
              )}

              {/* Event Feed */}
              <div className="bg-slate-900/80 p-4 rounded-3xl border border-slate-700/50 h-48 overflow-y-auto">
                <h4 className="text-xs font-black uppercase text-slate-500 mb-3 tracking-widest flex items-center gap-2">
                  <History size={14} /> Histórico Recente
                </h4>
                {matchState.events.length === 0 ? (
                  <p className="text-slate-600 text-sm italic">Nenhum evento registrado ainda...</p>
                ) : (
                  matchState.events.map(e => (
                    <div key={e.id} className="flex gap-3 text-sm py-2 border-b border-slate-800 last:border-0">
                      <span className="font-mono text-blue-400 font-bold">{e.minute}'</span>
                      <span className="font-medium text-slate-300">{e.description}</span>
                    </div>
                  ))
                )}
