            </div>

            {/* Right Sidebar - Away Team */}
            <div className="lg:col-span-3 bg-slate-800/30 p-4 rounded-3xl border border-slate-700/50">
              <PlayerList team={matchState.awayTeam} onPlayerClick={(p) => setCommandText(`Ação do jogador ${p.name}`)} />
            </div>
          </div>
        )}

        {activeTab === 'stats' && <MatchStats state={matchState} />}

        {activeTab === 'report' && (
          <div className="bg-slate-800 p-8 rounded-3xl border border-slate-700 min-h-[60vh] flex flex-col">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-black flex items-center gap-2">
                <FileText className="text-blue-400" /> Relatório da Partida
              </h2>
              <button 
                onClick={createReport} 
                disabled={isGeneratingReport}
                className="bg-blue-600 hover:bg-blue-500 disabled:bg-slate-700 px-6 py-2 rounded-xl font-bold flex items-center gap-2 transition-all"
              >
                {isGeneratingReport ? 'Gerando...' : 'Gerar com IA'}
              </button>
            </div>

            <div className="flex-1 bg-slate-900/50 p-6 rounded-2xl overflow-y-auto prose prose-invert max-w-none">
              {finalReport ? (
                <div dangerouslySetInnerHTML={{ __html: finalReport.replace(/\n/g, '<br/>') }} />
              ) : (
                <div className="flex flex-col items-center justify-center h-full text-slate-500 italic">
                   <p>Nenhum relatório gerado.</p>
                   <p className="text-xs">Clique no botão acima para compilar os eventos em um relatório profissional.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      {/* Persistent Smart Command Bar */}
      <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-2xl px-4 z-50">
        <form 
          onSubmit={handleCommand}
          className="bg-slate-800 p-2 rounded-2xl shadow-2xl border border-slate-700 flex items-center gap-2 ring-4 ring-slate-900/50 backdrop-blur-xl"
        >
          <button 
            type="button"
            onClick={handleVoiceInput}
            className={`p-3 rounded-xl transition-all ${isRecording ? 'bg-red-600 animate-pulse' : 'bg-slate-700 hover:bg-slate-600'}`}
          >
            <Mic size={24} className="text-white" />
          </button>

          <div className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
            <input 
              type="text" 
              placeholder="Descreva o que aconteceu (ex: 'Cartão amarelo número 8 casa')"
              className="w-full bg-slate-900/80 border border-slate-700 rounded-xl py-3 pl-10 pr-4 focus:outline-none focus:ring-2 focus:ring-blue-500 font-medium placeholder:text-slate-600"
              value={commandText}
              onChange={(e) => setCommandText(e.target.value)}
            />
          </div>

          <button 
            type="submit"
            className="p-3 bg-blue-600 hover:bg-blue-500 rounded-xl text-white font-bold transition-all shadow-lg active:scale-95"
          >
            <ArrowRightLeft size={24} />
          </button>
        </form>
      </div>

      {/* Undo Confirmation Overlay */}
      {showUndoConfirm && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="bg-slate-800 p-8 rounded-3xl border border-slate-700 max-w-sm w-full shadow-2xl">
            <h3 className="text-xl font-black mb-2">Desfazer última ação?</h3>
            <p className="text-slate-400 text-sm mb-6 font-medium">Isso irá restaurar o estado da partida para o momento imediatamente anterior ao último evento.</p>
            <div className="flex gap-3">
              <button 
                onClick={handleUndo}
                className="flex-1 bg-red-600 hover:bg-red-500 py-3 rounded-xl font-bold transition-all"
              >
                Confirmar
              </button>
              <button 
                onClick={() => setShowUndoConfirm(false)}
                className="flex-1 bg-slate-700 hover:bg-slate-600 py-3 rounded-xl font-bold transition-all"
              >
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

