import { GoogleGenAI, Type } from "@google/genai";
import { AICommandResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const parsePlayersFromImage = async (base64Image: string): Promise<any> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image,
          },
        },
        {
          text: `Extract the football player list and team names from this image. 
          Return a JSON object. 
          Each team should have 'teamName' (string) and 'players' (array of objects with 'name' and 'number'). 
          Return two teams: teamA and teamB.`
        }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          teamA: {
            type: Type.OBJECT,
            properties: {
              teamName: { type: Type.STRING },
              players: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    number: { type: Type.NUMBER }
                  }
                }
              }
            }
          },
          teamB: {
            type: Type.OBJECT,
            properties: {
              teamName: { type: Type.STRING },
              players: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    number: { type: Type.NUMBER }
                  }
                }
              }
            }
          }
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const processVoiceCommand = async (command: string, context: string): Promise<AICommandResponse> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze this match narration command: "${command}". 
    Context: ${context}.
    Identify the event type (GOAL, YELLOW_CARD, RED_CARD, SUBSTITUTION, SHOT, FOUL, CORNER), the team ('home' or 'away'), and player numbers involved.
    Return JSON.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          type: { type: Type.STRING },
          team: { type: Type.STRING },
          playerNumber: { type: Type.NUMBER },
          playerInNumber: { type: Type.NUMBER },
          playerOutNumber: { type: Type.NUMBER },
          description: { type: Type.STRING }
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateMatchReport = async (events: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Based on these match events: ${events}, write a professional, engaging summary report of the football match as a narrator would describe the final results and highlights. Use Markdown.`
  });
  return response.text || "Report generation failed.";
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  LayoutGrid, 
  List, 
  Mic, 
  Camera, 
  Settings, 
  History, 
  Save, 
  RotateCcw, 
  Play, 
  Pause,
  MessageSquare,
  FileText,
  BarChart2,
  Trophy,
  ArrowRightLeft,
  Search,
  Type as TypeIcon,
  X,
  Edit2
} from 'lucide-react';
import { 
  MatchState, 
  Player, 
  Team, 
  MatchEvent, 
  EventType, 
  Position 
} from './types';
import { 
  DEFAULT_HOME_TEAM, 
  DEFAULT_AWAY_TEAM, 
  STORAGE_KEY 
} from './constants';
import Field from './components/Field';
import PlayerList from './components/PlayerList';
import MatchStats from './components/MatchStats';
import { parsePlayersFromImage, processVoiceCommand, generateMatchReport } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'main' | 'stats' | 'report'>('main');
  const [viewMode, setViewMode] = useState<'field' | 'list'>('field');
  const [matchState, setMatchState] = useState<MatchState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : {
      homeTeam: DEFAULT_HOME_TEAM,
      awayTeam: DEFAULT_AWAY_TEAM,
      events: [],
      startTime: null,
      currentTime: 0,
      isPaused: true,
    };
  });

  const [history, setHistory] = useState<MatchState[]>([]);
  const [isRecording, setIsRecording] = useState(false);
  const [commandText, setCommandText] = useState('');
  const [finalReport, setFinalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [showUndoConfirm, setShowUndoConfirm] = useState(false);

  // Text Input Modal States
  const [showTextInputModal, setShowTextInputModal] = useState<{show: boolean, teamId: 'home' | 'away'}>({ show: false, teamId: 'home' });
  const [manualText, setManualText] = useState('');
  const [isEditingNames, setIsEditingNames] = useState<{home: boolean, away: boolean}>({ home: false, away: false });

  // Auto-save logic
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(matchState));
  }, [matchState]);

  // Match clock logic
  useEffect(() => {
    let interval: any;
    if (!matchState.isPaused && matchState.startTime) {
      interval = setInterval(() => {
        setMatchState(prev => ({
          ...prev,
          currentTime: prev.currentTime + 1
        }));
      }, 60000);
    }
    return () => clearInterval(interval);
  }, [matchState.isPaused, matchState.startTime]);

  const saveToHistory = useCallback(() => {
    setHistory(prev => [...prev.slice(-10), JSON.parse(JSON.stringify(matchState))]);
  }, [matchState]);

  const addEvent = (eventData: Omit<MatchEvent, 'id' | 'timestamp' | 'minute'>) => {
    saveToHistory();
    const newEvent: MatchEvent = {
      ...eventData,
      id: Math.random().toString(36).substr(2, 9),
      minute: matchState.currentTime,
      timestamp: Date.now(),
    };

    setMatchState(prev => {
      const updateTeam = (team: Team) => ({
        ...team,
        players: team.players.map(p => 
          p.id === newEvent.playerId || p.id === newEvent.relatedPlayerId
          ? { ...p, events: [...p.events, newEvent] }
          : p
        )
      });

      return {
        ...prev,
        events: [newEvent, ...prev.events],
        homeTeam: updateTeam(prev.homeTeam),
        awayTeam: updateTeam(prev.awayTeam),
      };
    });
  };

  const handleUndo = () => {
    if (history.length > 0) {
      setMatchState(history[history.length - 1]);
      setHistory(prev => prev.slice(0, -1));
      setShowUndoConfirm(false);
    }
  };

  const handleCommand = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!commandText.trim()) return;

    try {
      const result = await processVoiceCommand(commandText, `Match minute ${matchState.currentTime}. Home: ${matchState.homeTeam.name}, Away: ${matchState.awayTeam.name}`);

      if (result.type !== 'INVALID') {
        const team = result.team === 'home' ? matchState.homeTeam : matchState.awayTeam;
        const player = team.players.find(p => p.number === result.playerNumber);

        addEvent({
          type: result.type as EventType,
          teamId: result.team as 'home' | 'away',
          playerId: player?.id,
          description: result.description
        });
        setCommandText('');
      } else {
        alert("Comando não reconhecido. Tente algo como: 'Gol do número 10 do time casa'");
      }
    } catch (error) {
      console.error(error);
    }
  };

  const processPlayerList = (list: any[], teamId: 'home' | 'away') => {
    return list.map((p: any, i: number) => {
      const names = p.name.trim().split(' ');
      const shortName = names.length > 1 ? names[0] : p.name;
      return {
        id: Math.random().toString(36).substr(2, 9),
        fullName: p.name,
        name: shortName,
        number: p.number || (i + 1),
        teamId,
        isStarter: i < 11,
        position: (i === 0 ? 'GK' : i < 5 ? 'DF' : i < 9 ? 'MF' : 'FW') as Position,
        events: []
      } as Player;
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result?.toString().split(',')[1];
      if (base64) {
        try {
          const data = await parsePlayersFromImage(base64);
          setMatchState(prev => ({
            ...prev,
            homeTeam: { 
              ...prev.homeTeam, 
              name: data.teamA?.teamName || prev.homeTeam.name,
              players: processPlayerList(data.teamA?.players || [], 'home') 
            },
            awayTeam: { 
              ...prev.awayTeam, 
              name: data.teamB?.teamName || prev.awayTeam.name,
              players: processPlayerList(data.teamB?.players || [], 'away') 
            }
          }));
        } catch (error) {
          alert("Erro ao processar imagem.");
        }
      }
    };
    reader.readAsDataURL(file);
  };

  const handleManualTextInput = () => {
    const lines = manualText.split('\n');
    const players = lines.filter(l => l.trim()).map(line => {
      // Simple regex to find a number and a name
      const numMatch = line.match(/\d+/);
      const name = line.replace(/\d+/g, '').trim();
      return { name, number: numMatch ? parseInt(numMatch[0]) : 0 };
    });

    setMatchState(prev => ({
      ...prev,
      [showTextInputModal.teamId === 'home' ? 'homeTeam' : 'awayTeam']: {
        ...prev[showTextInputModal.teamId === 'home' ? 'homeTeam' : 'awayTeam'],
        players: processPlayerList(players, showTextInputModal.teamId)
      }
    }));
    setManualText('');
    setShowTextInputModal({ show: false, teamId: 'home' });
  };

  const updateTeamName = (teamId: 'home' | 'away', name: string) => {
    setMatchState(prev => ({
      ...prev,
      [teamId === 'home' ? 'homeTeam' : 'awayTeam']: {
        ...prev[teamId === 'home' ? 'homeTeam' : 'awayTeam'],
        name
      }
    }));
  };

  const createReport = async () => {
    setIsGeneratingReport(true);
    const eventLog = matchState.events.map(e => `${e.minute}': ${e.description}`).join('\n');
    const report = await generateMatchReport(eventLog);
    setFinalReport(report);
    setActiveTab('report');
    setIsGeneratingReport(false);
  };

  const handleVoiceInput = () => {
    setIsRecording(!isRecording);
    // Note: Use aistudio native voice transcription integration here if available in browser
  };

  return (
    <div className="min-h-screen flex flex-col max-w-7xl mx-auto p-4 md:p-6 pb-24">
      {/* Header */}
      <header className="flex justify-between items-center mb-8 bg-slate-800/50 p-4 rounded-2xl border border-slate-700 backdrop-blur-md shadow-lg">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-blue-600 rounded-xl">
            <Trophy className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-black uppercase tracking-tighter">Narrador Pro</h1>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Match Assistant AI</p>
          </div>
        </div>

        <div className="flex gap-2">
          <button 
            onClick={() => setMatchState(p => ({ ...p, isPaused: !p.isPaused, startTime: p.startTime || Date.now() }))}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black transition-all shadow-md ${
              matchState.isPaused ? 'bg-emerald-600 hover:bg-emerald-500' : 'bg-red-600 hover:bg-red-500'
            }`}
          >
            {matchState.isPaused ? <Play size={20} fill="currentColor" /> : <Pause size={20} fill="currentColor" />}
            {matchState.currentTime}'
          </button>
          <button onClick={() => setShowUndoConfirm(true)} className="p-3 bg-slate-700 hover:bg-slate-600 rounded-xl transition-all shadow-md">
            <RotateCcw size={20} />
          </button>
        </div>
      </header>

      {/* Main Tabs */}
      <nav className="flex gap-2 mb-6 bg-slate-900/50 p-1.5 rounded-2xl border border-slate-700 self-center">
        <button 
          onClick={() => setActiveTab('main')}
          className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all ${activeTab === 'main' ? 'bg-slate-700 text-white shadow-inner' : 'text-slate-400 hover:text-white'}`}
        >
          <LayoutGrid size={18} /> Campo
        </button>
        <button 
          onClick={() => setActiveTab('stats')}
          className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all ${activeTab === 'stats' ? 'bg-slate-700 text-white shadow-inner' : 'text-slate-400 hover:text-white'}`}
        >
          <BarChart2 size={18} /> Estatísticas
        </button>
        <button 
          onClick={() => setActiveTab('report')}
          className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all ${activeTab === 'report' ? 'bg-slate-700 text-white shadow-inner' : 'text-slate-400 hover:text-white'}`}
        >
          <FileText size={18} /> Relatório
        </button>
      </nav>

      {/* Content Area */}
      <main className="flex-1 mb-8 overflow-hidden rounded-3xl">
        {activeTab === 'main' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full">
            {/* Left Sidebar - Home Team */}
            <div className="lg:col-span-3 bg-slate-800/30 p-4 rounded-3xl border border-slate-700/50 flex flex-col gap-4 shadow-xl">
              <div className="flex items-center justify-between px-2">
                {isEditingNames.home ? (
                  <input 
                    autoFocus
                    className="bg-slate-900 border border-blue-500 rounded px-2 py-1 text-lg font-bold w-full"
                    value={matchState.homeTeam.name}
                    onBlur={() => setIsEditingNames(p => ({...p, home: false}))}
                    onChange={(e) => updateTeamName('home', e.target.value)}
                  />
                ) : (
                  <h2 className="text-xl font-black truncate flex items-center gap-2">
                    {matchState.homeTeam.name}
                    <button onClick={() => setIsEditingNames(p => ({...p, home: true}))} className="text-slate-500 hover:text-blue-400">
                      <Edit2 size={14} />
                    </button>
                  </h2>
                )}
              </div>
              <PlayerList team={matchState.homeTeam} onPlayerClick={(p) => setCommandText(`Ação do jogador ${p.name}`)} />
              <div className="flex gap-2 mt-auto">
                <label className="flex-1 cursor-pointer flex items-center justify-center gap-2 p-3 bg-slate-700 hover:bg-slate-600 rounded-xl text-xs font-bold transition-colors shadow-sm">
                  <Camera size={14} /> Foto
                  <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
                </label>
                <button 
                  onClick={() => setShowTextInputModal({ show: true, teamId: 'home' })}
                  className="flex-1 flex items-center justify-center gap-2 p-3 bg-slate-700 hover:bg-slate-600 rounded-xl text-xs font-bold transition-colors shadow-sm"
                >
                  <TypeIcon size={14} /> Texto
                </button>
              </div>
            </div>

            {/* Middle - Field View */}
            <div className="lg:col-span-6 flex flex-col gap-4">
              <div className="flex justify-center gap-2 mb-2">
                <button 
                  onClick={() => setViewMode('field')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl transition-all font-bold ${viewMode === 'field' ? 'bg-blue-600 text-white shadow-lg' : 'bg-slate-800 text-slate-400'}`}
                >
                  <LayoutGrid size={18} /> Campo
                </button>
                <button 
                  onClick={() => setViewMode('list')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-xl transition-all font-bold ${viewMode === 'list' ? 'bg-blue-600 text-white shadow-lg' : 'bg-slate-800 text-slate-400'}`}
                >
                  <List size={18} /> Lista
                </button>
              </div>

              {viewMode === 'field' ? (
                <Field 
                  homeTeam={matchState.homeTeam} 
                  awayTeam={matchState.awayTeam} 
                  onPlayerClick={(p) => setCommandText(`Evento para ${p.name}`)}
                />
              ) : (
                <div className="grid grid-cols-2 gap-4 h-[400px]">
                   <div className="bg-slate-800/40 p-4 rounded-3xl border border-slate-700/50"><PlayerList team={matchState.homeTeam} /></div>
                   <div className="bg-slate-800/40 p-4 rounded-3xl border border-slate-700/50"><PlayerList team={matchState.awayTeam} /></div>
                </div>
              )}

              {/* Event Feed */}
              <div className="bg-slate-900/80 p-5 rounded-3xl border border-slate-700/50 h-56 overflow-y-auto shadow-inner">
                <h4 className="text-[10px] font-black uppercase text-slate-500 mb-4 tracking-[0.2em] flex items-center gap-2">
                  <History size={12} /> Feed de Eventos da Partida
                </h4>
                {matchState.events.length === 0 ? (
                  <p className="text-slate-600 text-sm italic py-8 text-center">Nenhum evento registrado. Utilize a barra de comandos abaixo.</p>
                ) : (
                  matchState.events.map(e => (
                    <div key={e.id} className="flex gap-4 text-sm py-3 border-b border-slate-800/50 last:border-0 items-start group">
                      <span className="font-mono text-blue-400 font-black bg-blue-500/10 px-2 py-0.5 rounded">{e.minute}'</span>
                      <span className="font-medium text-slate-300 group-hover:text-white transition-colors">{e.description}</span>
                    </div>
                  ))
                )}
              </div>
            </div>

            {/* Right Sidebar - Away Team */}
            <div className="lg:col-span-3 bg-slate-800/30 p-4 rounded-3xl border border-slate-700/50 flex flex-col gap-4 shadow-xl">
              <div className="flex items-center justify-between px-2">
                {isEditingNames.away ? (
                  <input 
                    autoFocus
                    className="bg-slate-900 border border-blue-500 rounded px-2 py-1 text-lg font-bold w-full"
                    value={matchState.awayTeam.name}
                    onBlur={() => setIsEditingNames(p => ({...p, away: false}))}
                    onChange={(e) => updateTeamName('away', e.target.value)}
                  />
                ) : (
                  <h2 className="text-xl font-black truncate flex items-center gap-2">
                    {matchState.awayTeam.name}
                    <button onClick={() => setIsEditingNames(p => ({...p, away: true}))} className="text-slate-500 hover:text-blue-400">
                      <Edit2 size={14} />
                    </button>
                  </h2>
                )}
              </div>
              <PlayerList team={matchState.awayTeam} onPlayerClick={(p) => setCommandText(`Ação do jogador ${p.name}`)} />
              <div className="flex gap-2 mt-auto">
                <label className="flex-1 cursor-pointer flex items-center justify-center gap-2 p-3 bg-slate-700 hover:bg-slate-600 rounded-xl text-xs font-bold transition-colors shadow-sm">
                  <Camera size={14} /> Foto
                  <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
                </label>
                <button 
                  onClick={() => setShowTextInputModal({ show: true, teamId: 'away' })}
                  className="flex-1 flex items-center justify-center gap-2 p-3 bg-slate-700 hover:bg-slate-600 rounded-xl text-xs font-bold transition-colors shadow-sm"
                >
                  <TypeIcon size={14} /> Texto
                </button>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'stats' && <MatchStats state={matchState} />}

        {activeTab === 'report' && (
          <div className="bg-slate-800 p-8 rounded-3xl border border-slate-700 min-h-[60vh] flex flex-col shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-black flex items-center gap-2">
                <FileText className="text-blue-400" /> Relatório da Partida
              </h2>
              <button 
                onClick={createReport} 
                disabled={isGeneratingReport}
                className="bg-blue-600 hover:bg-blue-500 disabled:bg-slate-700 px-8 py-3 rounded-2xl font-black flex items-center gap-2 transition-all shadow-lg active:scale-95"
              >
                {isGeneratingReport ? 'Gerando Resumo...' : 'Compilar Narrativa IA'}
              </button>
            </div>

            <div className="flex-1 bg-slate-900/50 p-8 rounded-2xl overflow-y-auto prose prose-invert max-w-none border border-slate-700/50">
              {finalReport ? (
                <div dangerouslySetInnerHTML={{ __html: finalReport.replace(/\n/g, '<br/>') }} />
              ) : (
                <div className="flex flex-col items-center justify-center h-full text-slate-500 italic space-y-4">
                   <div className="p-6 bg-slate-800 rounded-full border border-slate-700"><FileText size={48} className="opacity-20" /></div>
                   <p className="text-lg">Pronto para gerar o relatório final?</p>
                   <p className="text-xs max-w-xs text-center">Iremos analisar todos os eventos cronológicos e criar uma narrativa profissional do jogo.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      {/* Persistent Smart Command Bar */}
      <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-3xl px-4 z-50">
        <form 
          onSubmit={handleCommand}
          className="bg-slate-800/80 p-2.5 rounded-3xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] border border-slate-700/50 flex items-center gap-3 ring-8 ring-slate-900/40 backdrop-blur-2xl"
        >
          <button 
            type="button"
            onClick={handleVoiceInput}
            className={`p-4 rounded-2xl transition-all shadow-md ${isRecording ? 'bg-red-600 animate-pulse' : 'bg-slate-700 hover:bg-slate-600'}`}
          >
            <Mic size={24} className="text-white" />
          </button>

          <div className="flex-1 relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={20} />
            <input 
              type="text" 
              placeholder="Ex: 'Gol do camisa 10', 'Substituição no time visitante', 'Cartão para o 5'..."
              className="w-full bg-slate-900 border border-slate-700/50 rounded-2xl py-4 pl-12 pr-4 focus:outline-none focus:ring-2 focus:ring-blue-500/50 font-bold text-lg placeholder:text-slate-600 transition-all"
              value={commandText}
              onChange={(e) => setCommandText(e.target.value)}
            />
          </div>

          <button 
            type="submit"
            className="p-4 bg-blue-600 hover:bg-blue-500 rounded-2xl text-white font-black transition-all shadow-lg shadow-blue-900/20 active:scale-95 flex items-center justify-center min-w-[64px]"
          >
            <ArrowRightLeft size={24} />
          </button>
        </form>
      </div>

      {/* Manual Text Input Modal */}
      {showTextInputModal.show && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-md flex items-center justify-center z-[110] p-4">
          <div className="bg-slate-800 p-8 rounded-[2rem] border border-slate-700 max-w-lg w-full shadow-[0_0_100px_rgba(0,0,0,0.8)]">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-2xl font-black">Importar {showTextInputModal.teamId === 'home' ? 'Time Casa' : 'Visitante'}</h3>
              <button onClick={() => setShowTextInputModal({ show: false, teamId: 'home' })} className="text-slate-500 hover:text-white">
                <X size={24} />
              </button>
            </div>
            <p className="text-slate-400 text-sm mb-4">Cole a lista de jogadores no formato "Número Nome" ou "Nome Número" (um por linha).</p>
            <textarea 
              className="w-full h-64 bg-slate-900 border border-slate-700 rounded-2xl p-4 font-mono text-sm focus:ring-2 focus:ring-blue-500 outline-none"
              placeholder="10 Pelé&#10;7 Garrincha&#10;5 Falcão..."
              value={manualText}
              onChange={(e) => setManualText(e.target.value)}
            />
            <div className="flex gap-4 mt-8">
              <button 
                onClick={handleManualTextInput}
                className="flex-1 bg-blue-600 hover:bg-blue-500 py-4 rounded-2xl font-black transition-all shadow-lg active:scale-95"
              >
                Processar Lista
              </button>
              <button 
                onClick={() => setShowTextInputModal({ show: false, teamId: 'home' })}
                className="px-6 py-4 bg-slate-700 hover:bg-slate-600 rounded-2xl font-black transition-all"
              >
                Cancelar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Undo Confirmation Overlay */}
      {showUndoConfirm && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="bg-slate-800 p-8 rounded-[2rem] border border-slate-700 max-w-sm w-full shadow-2xl">
            <h3 className="text-2xl font-black mb-3">Desfazer ação?</h3>
            <p className="text-slate-400 text-sm mb-8 font-medium leading-relaxed">Isso irá remover o último evento registrado do histórico e restaurar as estatísticas anteriores.</p>
            <div className="flex gap-4">
              <button 
                onClick={handleUndo}
                className="flex-1 bg-red-600 hover:bg-red-500 py-4 rounded-2xl font-black transition-all shadow-lg"
              >
                Confirmar
              </button>
              <button 
                onClick={() => setShowUndoConfirm(false)}
                className="flex-1 bg-slate-700 hover:bg-slate-600 py-4 rounded-2xl font-black transition-all"
              >
                Voltar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { AICommandResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const parsePlayersFromImage = async (base64Image: string): Promise<any> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image,
          },
        },
        {
          text: `Extract the football player list and the team name from this image. 
          Return a JSON object with 'teamName' (string) and 'players' (array of objects with 'name' and 'number'). 
          If there are multiple teams in the image, extract the primary one or the one that is clearly a list.`
        }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          teamName: { type: Type.STRING, description: "The name of the football team found in the image" },
          players: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING, description: "Full name of the player" },
                number: { type: Type.NUMBER, description: "Jersey number of the player" }
              }
            }
          }
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const processVoiceCommand = async (command: string, context: string): Promise<AICommandResponse> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze this match narration command: "${command}". 
    Context: ${context}.
    Identify the event type (GOAL, YELLOW_CARD, RED_CARD, SUBSTITUTION, SHOT, FOUL, CORNER), the team ('home' or 'away'), and player numbers involved.
    Return JSON.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          type: { type: Type.STRING },
          team: { type: Type.STRING },
          playerNumber: { type: Type.NUMBER },
          playerInNumber: { type: Type.NUMBER },
          playerOutNumber: { type: Type.NUMBER },
          description: { type: Type.STRING }
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateMatchReport = async (events: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Based on these match events: ${events}, write a professional, engaging summary report of the football match as a narrator would describe the final results and highlights. Use Markdown.`
  });
  return response.text || "Report generation failed.";
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  LayoutGrid, 
  List, 
  Mic, 
  Camera, 
  Settings, 
  History, 
  Save, 
  RotateCcw, 
  Play, 
  Pause,
  MessageSquare,
  FileText,
  BarChart2,
  Trophy,
  ArrowRightLeft,
  Search,
  Type as TypeIcon,
  X,
  Edit2,
  Loader2
} from 'lucide-react';
import { 
  MatchState, 
  Player, 
  Team, 
  MatchEvent, 
  EventType, 
  Position 
} from './types';
import { 
  DEFAULT_HOME_TEAM, 
  DEFAULT_AWAY_TEAM, 
  STORAGE_KEY 
} from './constants';
import Field from './components/Field';
import PlayerList from './components/PlayerList';
import MatchStats from './components/MatchStats';
import { parsePlayersFromImage, processVoiceCommand, generateMatchReport } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'main' | 'stats' | 'report'>('main');
  const [viewMode, setViewMode] = useState<'field' | 'list'>('field');
  const [matchState, setMatchState] = useState<MatchState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : {
      homeTeam: DEFAULT_HOME_TEAM,
      awayTeam: DEFAULT_AWAY_TEAM,
      events: [],
      startTime: null,
      currentTime: 0,
      isPaused: true,
    };
  });

  const [history, setHistory] = useState<MatchState[]>([]);
  const [isRecording, setIsRecording] = useState(false);
  const [commandText, setCommandText] = useState('');
  const [finalReport, setFinalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [showUndoConfirm, setShowUndoConfirm] = useState(false);
  const [isProcessingImage, setIsProcessingImage] = useState<false | 'home' | 'away'>(false);

  // Text Input Modal States
  const [showTextInputModal, setShowTextInputModal] = useState<{show: boolean, teamId: 'home' | 'away'}>({ show: false, teamId: 'home' });
  const [manualText, setManualText] = useState('');
  const [isEditingNames, setIsEditingNames] = useState<{home: boolean, away: boolean}>({ home: false, away: false });

  // Auto-save logic
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(matchState));
  }, [matchState]);

  // Match clock logic
  useEffect(() => {
    let interval: any;
    if (!matchState.isPaused && matchState.startTime) {
      interval = setInterval(() => {
        setMatchState(prev => ({
          ...prev,
          currentTime: prev.currentTime + 1
        }));
      }, 60000);
    }
    return () => clearInterval(interval);
  }, [matchState.isPaused, matchState.startTime]);

  const saveToHistory = useCallback(() => {
    setHistory(prev => [...prev.slice(-10), JSON.parse(JSON.stringify(matchState))]);
  }, [matchState]);

  const addEvent = (eventData: Omit<MatchEvent, 'id' | 'timestamp' | 'minute'>) => {
    saveToHistory();
    const newEvent: MatchEvent = {
      ...eventData,
      id: Math.random().toString(36).substr(2, 9),
      minute: matchState.currentTime,
      timestamp: Date.now(),
    };

    setMatchState(prev => {
      const updateTeam = (team: Team) => ({
        ...team,
        players: team.players.map(p => 
          p.id === newEvent.playerId || p.id === newEvent.relatedPlayerId
          ? { ...p, events: [...p.events, newEvent] }
          : p
        )
      });

      return {
        ...prev,
        events: [newEvent, ...prev.events],
        homeTeam: updateTeam(prev.homeTeam),
        awayTeam: updateTeam(prev.awayTeam),
      };
    });
  };

  const handleUndo = () => {
    if (history.length > 0) {
      setMatchState(history[history.length - 1]);
      setHistory(prev => prev.slice(0, -1));
      setShowUndoConfirm(false);
    }
  };

  const handleCommand = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!commandText.trim()) return;

    try {
      const result = await processVoiceCommand(commandText, `Match minute ${matchState.currentTime}. Home: ${matchState.homeTeam.name}, Away: ${matchState.awayTeam.name}`);

      if (result.type !== 'INVALID') {
        const teamId = result.team === 'home' ? 'homeTeam' : 'awayTeam';
        const team = matchState[teamId];
        const player = team.players.find(p => p.number === result.playerNumber);

        addEvent({
          type: result.type as EventType,
          teamId: result.team as 'home' | 'away',
          playerId: player?.id,
          description: result.description
        });
        setCommandText('');
      } else {
        alert("Comando não reconhecido. Tente algo como: 'Gol do número 10 do time casa'");
      }
    } catch (error) {
      console.error(error);
    }
  };

  const processPlayerList = (list: any[], teamId: 'home' | 'away') => {
    return list.map((p: any, i: number) => {
      const names = p.name.trim().split(' ');
      // Use first name by default, append second if duplicate exists in the list
      let shortName = names.length > 1 ? names[0] : p.name;

      const duplicates = list.filter(other => {
        const otherNames = other.name.trim().split(' ');
        return otherNames[0] === names[0] && other !== p;
      });

      if (duplicates.length > 0 && names.length > 1) {
        shortName = `${names[0]} ${names[1]}`;
      }

      return {
        id: Math.random().toString(36).substr(2, 9),
        fullName: p.name,
        name: shortName,
        number: p.number || (i + 1),
        teamId,
        isStarter: i < 11,
        position: (i === 0 ? 'GK' : i < 5 ? 'DF' : i < 9 ? 'MF' : 'FW') as Position,
        events: []
      } as Player;
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, teamId: 'home' | 'away') => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessingImage(teamId);
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result?.toString().split(',')[1];
      if (base64) {
        try {
          const data = await parsePlayersFromImage(base64);
          setMatchState(prev => {
            const targetTeamId = teamId === 'home' ? 'homeTeam' : 'awayTeam';
            return {
              ...prev,
              [targetTeamId]: { 
                ...prev[targetTeamId], 
                name: data.teamName || prev[targetTeamId].name,
                players: processPlayerList(data.players || [], teamId) 
              }
            };
          });
        } catch (error) {
          console.error(error);
          alert("Erro ao processar imagem para o time selecionado.");
        } finally {
          setIsProcessingImage(false);
          e.target.value = ''; // Reset input
        }
      }
    };
    reader.readAsDataURL(file);
  };

  const handleManualTextInput = () => {
    const lines = manualText.split('\n');
    const players = lines.filter(l => l.trim()).map(line => {
      const numMatch = line.match(/\d+/);
      const name = line.replace(/\d+/g, '').trim();
      return { name, number: numMatch ? parseInt(numMatch[0]) : 0 };
    });

    const teamKey = showTextInputModal.teamId === 'home' ? 'homeTeam' : 'awayTeam';
    setMatchState(prev => ({
      ...prev,
      [teamKey]: {
        ...prev[teamKey],
        players: processPlayerList(players, showTextInputModal.teamId)
      }
    }));
    setManualText('');
    setShowTextInputModal({ show: false, teamId: 'home' });
  };

  const updateTeamName = (teamId: 'home' | 'away', name: string) => {
    setMatchState(prev => ({
      ...prev,
      [teamId === 'home' ? 'homeTeam' : 'awayTeam']: {
        ...prev[teamId === 'home' ? 'homeTeam' : 'awayTeam'],
        name
      }
    }));
  };

  const createReport = async () => {
    setIsGeneratingReport(true);
    const eventLog = matchState.events.map(e => `${e.minute}': ${e.description}`).join('\n');
    const report = await generateMatchReport(eventLog);
    setFinalReport(report);
    setActiveTab('report');
    setIsGeneratingReport(false);
  };

  const handleVoiceInput = () => {
    setIsRecording(!isRecording);
  };

  return (
    <div className="min-h-screen flex flex-col max-w-7xl mx-auto p-4 md:p-6 pb-24">
      {/* Header */}
      <header className="flex justify-between items-center mb-8 bg-slate-800/50 p-4 rounded-2xl border border-slate-700 backdrop-blur-md shadow-lg">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-blue-600 rounded-xl shadow-lg shadow-blue-900/40">
            <Trophy className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-black uppercase tracking-tighter">Narrador Pro</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">Match Assistant AI</p>
          </div>
        </div>

        <div className="flex gap-2">
          <button 
            onClick={() => setMatchState(p => ({ ...p, isPaused: !p.isPaused, startTime: p.startTime || Date.now() }))}
            className={`flex items-center gap-2 px-6 py-2 rounded-xl font-black transition-all shadow-md active:scale-95 ${
              matchState.isPaused ? 'bg-emerald-600 hover:bg-emerald-500 text-white' : 'bg-red-600 hover:bg-red-500 text-white'
            }`}
          >
            {matchState.isPaused ? <Play size={20} fill="currentColor" /> : <Pause size={20} fill="currentColor" />}
            {matchState.currentTime}'
          </button>
          <button onClick={() => setShowUndoConfirm(true)} className="p-3 bg-slate-700 hover:bg-slate-600 rounded-xl transition-all shadow-md active:scale-95 text-slate-200">
            <RotateCcw size={20} />
          </button>
        </div>
      </header>

      {/* Main Tabs */}
      <nav className="flex gap-2 mb-6 bg-slate-900/50 p-1.5 rounded-2xl border border-slate-700 self-center shadow-inner">
        {(['main', 'stats', 'report'] as const).map((tab) => (
          <button 
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl font-bold transition-all ${activeTab === tab ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-400 hover:text-white hover:bg-slate-800/40'}`}
          >
            {tab === 'main' && <LayoutGrid size={18} />}
            {tab === 'stats' && <BarChart2 size={18} />}
            {tab === 'report' && <FileText size={18} />}
            {tab === 'main' ? 'Campo' : tab === 'stats' ? 'Estatísticas' : 'Relatório'}
          </button>
        ))}
      </nav>

      {/* Content Area */}
      <main className="flex-1 mb-8 overflow-hidden rounded-3xl">
        {activeTab === 'main' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full">
            {/* Teams Sides */}
            {(['home', 'away'] as const).map((side) => {
              const teamId = side === 'home' ? 'homeTeam' : 'awayTeam';
              const team = matchState[teamId];
              return (
                <div key={side} className={`lg:col-span-3 bg-slate-800/30 p-4 rounded-3xl border border-slate-700/50 flex flex-col gap-4 shadow-xl ${side === 'away' ? 'lg:order-3' : ''}`}>
                  <div className="flex items-center justify-between px-2">
                    {isEditingNames[side] ? (
                      <input 
                        autoFocus
                        className="bg-slate-900 border border-blue-500 rounded px-2 py-1 text-lg font-bold w-full focus:outline-none ring-2 ring-blue-500/20"
                        value={team.name}
                        onBlur={() => setIsEditingNames(p => ({...p, [side]: false}))}
                        onChange={(e) => updateTeamName(side, e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && setIsEditingNames(p => ({...p, [side]: false}))}
                      />
                    ) : (
                      <h2 className="text-xl font-black truncate flex items-center gap-2 group cursor-pointer" onClick={() => setIsEditingNames(p => ({...p, [side]: true}))}>
                        {team.name}
                        <Edit2 size={14} className="text-slate-500 opacity-0 group-hover:opacity-100 transition-opacity" />
                      </h2>
                    )}
                  </div>

                  <PlayerList team={team} onPlayerClick={(p) => setCommandText(`Ação do jogador ${p.name}`)} />

                  <div className="flex gap-2 mt-auto">
                    <label className={`flex-1 cursor-pointer flex items-center justify-center gap-2 p-3 rounded-xl text-xs font-bold transition-all shadow-sm ${isProcessingImage === side ? 'bg-slate-800 opacity-50' : 'bg-slate-700 hover:bg-slate-600 active:scale-95'}`}>
                      {isProcessingImage === side ? <Loader2 size={14} className="animate-spin" /> : <Camera size={14} />} 
                      Foto
                      <input 
                        type="file" 
                        className="hidden" 
                        accept="image/*" 
                        onChange={(e) => handleImageUpload(e, side)} 
                        disabled={!!isProcessingImage}
                      />
                    </label>
                    <button 
                      onClick={() => setShowTextInputModal({ show: true, teamId: side })}
                      className="flex-1 flex items-center justify-center gap-2 p-3 bg-slate-700 hover:bg-slate-600 active:scale-95 rounded-xl text-xs font-bold transition-all shadow-sm"
                    >
                      <TypeIcon size={14} /> Texto
                    </button>
                  </div>
                </div>
              );
            })}

            {/* Middle - Field View */}
            <div className="lg:col-span-6 flex flex-col gap-4 lg:order-2">
              <div className="flex justify-center gap-2 mb-2">
                <button 
                  onClick={() => setViewMode('field')}
                  className={`flex items-center gap-2 px-6 py-2 rounded-xl transition-all font-bold shadow-md ${viewMode === 'field' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}
                >
                  <LayoutGrid size={18} /> Campo
                </button>
                <button 
                  onClick={() => setViewMode('list')}
                  className={`flex items-center gap-2 px-6 py-2 rounded-xl transition-all font-bold shadow-md ${viewMode === 'list' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700'}`}
                >
                  <List size={18} /> Lista
                </button>
              </div>

              {viewMode === 'field' ? (
                <Field 
                  homeTeam={matchState.homeTeam} 
                  awayTeam={matchState.awayTeam} 
                  onPlayerClick={(p) => setCommandText(`Evento para ${p.name}`)}
                />
              ) : (
                <div className="grid grid-cols-2 gap-4 h-[440px]">
                   <div className="bg-slate-800/40 p-4 rounded-3xl border border-slate-700/50 shadow-inner overflow-hidden flex flex-col">
                      <PlayerList team={matchState.homeTeam} />
                   </div>
                   <div className="bg-slate-800/40 p-4 rounded-3xl border border-slate-700/50 shadow-inner overflow-hidden flex flex-col">
                      <PlayerList team={matchState.awayTeam} />
                   </div>
                </div>
              )}

              {/* Event Feed */}
              <div className="bg-slate-900/80 p-5 rounded-3xl border border-slate-700/50 h-56 overflow-y-auto shadow-[inset_0_2px_10px_rgba(0,0,0,0.3)]">
                <h4 className="text-[10px] font-black uppercase text-slate-500 mb-4 tracking-[0.3em] flex items-center gap-2">
                  <History size={12} /> Log da Partida
                </h4>
                {matchState.events.length === 0 ? (
                  <div className="flex flex-col items-center justify-center h-32 text-slate-600 italic">
                    <p className="text-sm">Inicie a narração para ver os eventos aqui.</p>
                  </div>
                ) : (
                  matchState.events.map(e => (
                    <div key={e.id} className="flex gap-4 text-sm py-3 border-b border-slate-800/50 last:border-0 items-start group">
                      <span className="font-mono text-blue-400 font-black bg-blue-500/10 px-2 py-0.5 rounded text-xs">{e.minute}'</span>
                      <span className="font-medium text-slate-300 group-hover:text-white transition-colors">{e.description}</span>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        )}

        {activeTab === 'stats' && <MatchStats state={matchState} />}

        {activeTab === 'report' && (
          <div className="bg-slate-800 p-8 rounded-3xl border border-slate-700 min-h-[60vh] flex flex-col shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-black flex items-center gap-2">
                <FileText className="text-blue-400" /> Relatório Narrativo
              </h2>
              <button 
                onClick={createReport} 
                disabled={isGeneratingReport}
                className="bg-blue-600 hover:bg-blue-500 disabled:bg-slate-700 px-8 py-3 rounded-2xl font-black flex items-center gap-2 transition-all shadow-lg active:scale-95 disabled:scale-100"
              >
                {isGeneratingReport ? <Loader2 size={18} className="animate-spin" /> : <FileText size={18} />}
                {isGeneratingReport ? 'Processando Eventos...' : 'Compilar Narrativa'}
              </button>
            </div>

            <div className="flex-1 bg-slate-900/50 p-8 rounded-2xl overflow-y-auto border border-slate-700/50 shadow-inner">
              {finalReport ? (
                <div className="prose prose-invert max-w-none text-slate-300 leading-relaxed font-medium" dangerouslySetInnerHTML={{ __html: finalReport.replace(/\n/g, '<br/>') }} />
              ) : (
                <div className="flex flex-col items-center justify-center h-full text-slate-500 italic space-y-4 py-20">
                   <div className="p-8 bg-slate-800 rounded-full border border-slate-700 shadow-xl"><FileText size={48} className="opacity-10" /></div>
                   <div className="text-center">
                    <p className="text-lg font-bold">Nenhum relatório gerado</p>
                    <p className="text-xs max-w-xs text-slate-600 mt-2 uppercase tracking-widest font-black">Clique em compilar para criar o resumo do narrador</p>
                   </div>
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      {/* Persistent Smart Command Bar */}
      <div className="fixed bottom-6 left-1/2 -translate-x-1/2 w-full max-w-3xl px-4 z-50">
        <form 
          onSubmit={handleCommand}
          className="bg-slate-800/90 p-2.5 rounded-[2.5rem] shadow-[0_30px_60px_rgba(0,0,0,0.6)] border border-white/10 flex items-center gap-3 ring-8 ring-slate-900/60 backdrop-blur-3xl"
        >
          <button 
            type="button"
            onClick={handleVoiceInput}
            className={`p-4 rounded-full transition-all shadow-xl active:scale-90 ${isRecording ? 'bg-red-600 animate-pulse ring-4 ring-red-500/20' : 'bg-slate-700 hover:bg-slate-600'}`}
          >
            <Mic size={24} className="text-white" />
          </button>

          <div className="flex-1 relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={22} />
            <input 
              type="text" 
              placeholder="Descreva o lance... Ex: 'Gol do 9 Casa'"
              className="w-full bg-slate-900/50 border border-slate-700/50 rounded-full py-4 pl-14 pr-4 focus:outline-none focus:ring-2 focus:ring-blue-500/50 font-bold text-lg placeholder:text-slate-600 text-white transition-all shadow-inner"
              value={commandText}
              onChange={(e) => setCommandText(e.target.value)}
            />
          </div>

          <button 
            type="submit"
            className="p-4 bg-blue-600 hover:bg-blue-500 rounded-full text-white font-black transition-all shadow-xl shadow-blue-900/30 active:scale-90 flex items-center justify-center min-w-[64px]"
          >
            <ArrowRightLeft size={24} />
          </button>
        </form>
      </div>

      {/* Manual Text Input Modal */}
      {showTextInputModal.show && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-xl flex items-center justify-center z-[110] p-4 animate-in fade-in duration-300">
          <div className="bg-slate-800 p-8 rounded-[3rem] border border-white/10 max-w-lg w-full shadow-[0_0_100px_rgba(0,0,0,0.9)] animate-in zoom-in-95 duration-300">
            <div className="flex justify-between items-center mb-8">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-blue-500/20 rounded-lg"><TypeIcon className="text-blue-400" size={24} /></div>
                <h3 className="text-2xl font-black">Importar: {matchState[showTextInputModal.teamId === 'home' ? 'homeTeam' : 'awayTeam'].name}</h3>
              </div>
              <button onClick={() => setShowTextInputModal({ show: false, teamId: 'home' })} className="text-slate-500 hover:text-white transition-colors p-2 bg-slate-900 rounded-full">
                <X size={24} />
              </button>
            </div>
            <p className="text-slate-400 text-sm mb-4 font-medium">Cole a lista de jogadores. Formatos aceitos: "Número Nome" ou "Nome Número".</p>
            <textarea 
              className="w-full h-72 bg-slate-900/80 border border-slate-700 rounded-3xl p-6 font-mono text-sm focus:ring-2 focus:ring-blue-500/50 outline-none shadow-inner resize-none text-blue-100"
              placeholder="Exemplo:&#10;1 Rogério Ceni&#10;2 Cafu&#10;5 Lugano..."
              value={manualText}
              onChange={(e) => setManualText(e.target.value)}
            />
            <div className="flex gap-4 mt-10">
              <button 
                onClick={handleManualTextInput}
                className="flex-1 bg-blue-600 hover:bg-blue-500 py-5 rounded-3xl font-black transition-all shadow-xl shadow-blue-900/20 active:scale-95 text-lg"
              >
                Carregar Jogadores
              </button>
              <button 
                onClick={() => setShowTextInputModal({ show: false, teamId: 'home' })}
                className="px-8 py-5 bg-slate-700 hover:bg-slate-600 rounded-3xl font-black transition-all text-slate-300 active:scale-95"
              >
                Voltar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Undo Confirmation Overlay */}
      {showUndoConfirm && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-md flex items-center justify-center z-[100] p-4">
          <div className="bg-slate-800 p-10 rounded-[3rem] border border-white/10 max-w-sm w-full shadow-2xl">
            <div className="w-16 h-16 bg-red-500/20 rounded-full flex items-center justify-center mx-auto mb-6 text-red-500">
              <RotateCcw size={32} />
            </div>
            <h3 className="text-2xl font-black mb-3 text-center">Desfazer evento?</h3>
            <p className="text-slate-400 text-sm mb-10 text-center font-medium leading-relaxed">Isso removerá a última entrada do log e restaurará as estatísticas anteriores da partida.</p>
            <div className="flex gap-4">
              <button 
                onClick={handleUndo}
                className="flex-1 bg-red-600 hover:bg-red-500 py-4 rounded-2xl font-black transition-all shadow-lg active:scale-95 text-white"
              >
                Confirmar
              </button>
              <button 
                onClick={() => setShowUndoConfirm(false)}
                className="flex-1 bg-slate-700 hover:bg-slate-600 py-4 rounded-2xl font-black transition-all active:scale-95 text-slate-300"
              >
                Manter
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type Position = 'GK' | 'DF' | 'MF' | 'FW';

export interface Player {
  id: string;
  name: string;
  fullName: string;
  number: number;
  position: Position;
  teamId: 'home' | 'away';
  isStarter: boolean;
  events: MatchEvent[];
}

export interface Team {
  id: 'home' | 'away';
  name: string;
  color: string;
  players: Player[];
}

export type EventType = 'GOAL' | 'YELLOW_CARD' | 'RED_CARD' | 'SUBSTITUTION' | 'SHOT' | 'FOUL' | 'CORNER' | 'PERIOD_START' | 'PERIOD_END';

export type MatchPeriod = 'PRE_MATCH' | '1T' | 'INTERVAL' | '2T' | 'ET' | 'FINISHED';

export interface MatchEvent {
  id: string;
  type: EventType;
  minute: number;
  playerId?: string;
  relatedPlayerId?: string; // e.g., assistant or sub-in
  teamId: 'home' | 'away' | 'none';
  description: string;
  timestamp: number;
}

export interface MatchState {
  homeTeam: Team;
  awayTeam: Team;
  events: MatchEvent[];
  startTime: number | null;
  currentTime: number; // match minute
  isPaused: boolean;
  period: MatchPeriod;
}

export interface AICommandResponse {
  type: EventType | 'INVALID';
  team?: 'home' | 'away';
  playerNumber?: number;
  playerInNumber?: number;
  playerOutNumber?: number;
  description: string;
}

import React, { useState, useEffect, useCallback } from 'react';
import { 
  LayoutGrid, 
  List, 
  Mic, 
  Camera, 
  RotateCcw, 
  Play, 
  Pause,
  FileText,
  BarChart2,
  Trophy,
  ArrowRightLeft,
  Search,
  Type as TypeIcon,
  X,
  Edit2,
  Loader2,
  Target,
  AlertCircle,
  Flag,
  ChevronRight,
  Trash2
} from 'lucide-react';
import { 
  MatchState, 
  Player, 
  Team, 
  MatchEvent, 
  EventType, 
  Position,
  MatchPeriod
} from './types';
import { 
  DEFAULT_HOME_TEAM, 
  DEFAULT_AWAY_TEAM, 
  STORAGE_KEY 
} from './constants';
import Field from './components/Field';
import PlayerList from './components/PlayerList';
import MatchStats from './components/MatchStats';
import { parsePlayersFromImage, processVoiceCommand, generateMatchReport } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'main' | 'stats' | 'report'>('main');
  const [viewMode, setViewMode] = useState<'field' | 'list'>('field');
  const [matchState, setMatchState] = useState<MatchState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : {
      homeTeam: DEFAULT_HOME_TEAM,
      awayTeam: DEFAULT_AWAY_TEAM,
      events: [],
      startTime: null,
      currentTime: 0,
      isPaused: true,
      period: 'PRE_MATCH'
    };
  });

  const [history, setHistory] = useState<MatchState[]>([]);
  const [isRecording, setIsRecording] = useState(false);
  const [commandText, setCommandText] = useState('');
  const [finalReport, setFinalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [showUndoConfirm, setShowUndoConfirm] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [isProcessingImage, setIsProcessingImage] = useState<false | 'home' | 'away'>(false);

  const [showTextInputModal, setShowTextInputModal] = useState<{show: boolean, teamId: 'home' | 'away'}>({ show: false, teamId: 'home' });
  const [manualText, setManualText] = useState('');
  const [isEditingNames, setIsEditingNames] = useState<{home: boolean, away: boolean}>({ home: false, away: false });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(matchState));
  }, [matchState]);

  useEffect(() => {
    let interval: any;
    if (!matchState.isPaused && matchState.period !== 'FINISHED' && matchState.period !== 'INTERVAL') {
      interval = setInterval(() => {
        setMatchState(prev => ({
          ...prev,
          currentTime: prev.currentTime + 1
        }));
      }, 60000);
    }
    return () => clearInterval(interval);
  }, [matchState.isPaused, matchState.period]);

  const saveToHistory = useCallback(() => {
    setHistory(prev => [...prev.slice(-10), JSON.parse(JSON.stringify(matchState))]);
  }, [matchState]);

  const addEvent = (eventData: Omit<MatchEvent, 'id' | 'timestamp' | 'minute'>) => {
    saveToHistory();
    const newEvent: MatchEvent = {
      ...eventData,
      id: Math.random().toString(36).substr(2, 9),
      minute: matchState.currentTime,
      timestamp: Date.now(),
    };

    setMatchState(prev => {
      const updateTeam = (team: Team) => ({
        ...team,
        players: team.players.map(p => 
          p.id === newEvent.playerId || p.id === newEvent.relatedPlayerId
          ? { ...p, events: [...p.events, newEvent] }
          : p
        )
      });

      return {
        ...prev,
        events: [newEvent, ...prev.events],
        homeTeam: updateTeam(prev.homeTeam),
        awayTeam: updateTeam(prev.awayTeam),
      };
    });
  };

  const handleUndo = () => {
    if (history.length > 0) {
      setMatchState(history[history.length - 1]);
      setHistory(prev => prev.slice(0, -1));
      setShowUndoConfirm(false);
    }
  };

  const handleReset = () => {
    const newState: MatchState = {
      homeTeam: { ...DEFAULT_HOME_TEAM, players: [] },
      awayTeam: { ...DEFAULT_AWAY_TEAM, players: [] },
      events: [],
      startTime: null,
      currentTime: 0,
      isPaused: true,
      period: 'PRE_MATCH'
    };
    setMatchState(newState);
    setHistory([]);
    setFinalReport('');
    setShowResetConfirm(false);
  };

  const nextPeriod = () => {
    const periods: MatchPeriod[] = ['PRE_MATCH', '1T', 'INTERVAL', '2T', 'FINISHED'];
    const currentIndex = periods.indexOf(matchState.period);
    if (currentIndex < periods.length - 1) {
      const newPeriod = periods[currentIndex + 1];
      saveToHistory();
      setMatchState(prev => ({
        ...prev,
        period: newPeriod,
        isPaused: newPeriod === 'INTERVAL' || newPeriod === 'FINISHED' || newPeriod === 'PRE_MATCH'
      }));
      addEvent({
        type: 'PERIOD_START',
        teamId: 'none',
        description: `Início: ${newPeriod}`
      });
    }
  };

  const handleQuickAction = (type: EventType, teamId: 'home' | 'away') => {
    const team = matchState[teamId === 'home' ? 'homeTeam' : 'awayTeam'];
    addEvent({
      type,
      teamId,
      description: `${type.replace('_', ' ')} para ${team.name}`
    });
  };

  const handleCommand = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!commandText.trim()) return;

    try {
      const result = await processVoiceCommand(commandText, `Match minute ${matchState.currentTime}. Home: ${matchState.homeTeam.name}, Away: ${matchState.awayTeam.name}`);
      if (result.type !== 'INVALID') {
        const teamId = result.team === 'home' ? 'homeTeam' : 'awayTeam';
        const team = matchState[teamId];
        const player = team.players.find(p => p.number === result.playerNumber);
        addEvent({
          type: result.type as EventType,
          teamId: result.team as 'home' | 'away',
          playerId: player?.id,
          description: result.description
        });
        setCommandText('');
      } else {
        alert("Comando não reconhecido.");
      }
    } catch (error) { console.error(error); }
  };

  const processPlayerList = (list: any[], teamId: 'home' | 'away') => {
    return list.map((p: any, i: number) => {
      const names = p.name.trim().split(' ');
      let shortName = names.length > 1 ? names[0] : p.name;
      return {
        id: Math.random().toString(36).substr(2, 9),
        fullName: p.name,
        name: shortName,
        number: p.number || (i + 1),
        teamId,
        isStarter: i < 11,
        position: (i === 0 ? 'GK' : i < 5 ? 'DF' : i < 9 ? 'MF' : 'FW') as Position,
        events: []
      } as Player;
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, teamId: 'home' | 'away') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingImage(teamId);
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result?.toString().split(',')[1];
      if (base64) {
        try {
          const data = await parsePlayersFromImage(base64);
          setMatchState(prev => ({
            ...prev,
            [teamId === 'home' ? 'homeTeam' : 'awayTeam']: { 
              ...prev[teamId === 'home' ? 'homeTeam' : 'awayTeam'], 
              name: data.teamName || prev[teamId === 'home' ? 'homeTeam' : 'awayTeam'].name,
              players: processPlayerList(data.players || [], teamId) 
            }
          }));
        } catch (error) { alert("Erro ao processar imagem."); } finally { setIsProcessingImage(false); e.target.value = ''; }
      }
    };
    reader.readAsDataURL(file);
  };

  const handleManualTextInput = () => {
    const lines = manualText.split('\n');
    const players = lines.filter(l => l.trim()).map(line => {
      const numMatch = line.match(/\d+/);
      const name = line.replace(/\d+/g, '').trim();
      return { name, number: numMatch ? parseInt(numMatch[0]) : 0 };
    });
    const teamKey = showTextInputModal.teamId === 'home' ? 'homeTeam' : 'awayTeam';
    setMatchState(prev => ({
      ...prev,
      [teamKey]: { ...prev[teamKey], players: processPlayerList(players, showTextInputModal.teamId) }
    }));
    setManualText('');
    setShowTextInputModal({ show: false, teamId: 'home' });
  };

  const getGoals = (teamId: 'home' | 'away') => 
    matchState.events.filter(e => e.teamId === teamId && e.type === 'GOAL').length;

  return (
    <div className="min-h-screen flex flex-col max-w-7xl mx-auto p-4 md:p-6 pb-32">
      {/* 
        PREMIUM MATCH CONTROL BAR 
        A central dashboard for match handling
      */}
      <div className="sticky top-4 z-[60] mb-8">
        <div className="bg-slate-900/95 border border-white/10 rounded-[2rem] shadow-[0_20px_50px_rgba(0,0,0,0.5)] backdrop-blur-2xl overflow-hidden ring-1 ring-white/5">
          <div className="flex flex-col md:flex-row items-stretch">

            {/* Left: Home Score & Info */}
            <div className="flex-1 flex items-center justify-end px-6 py-4 bg-gradient-to-l from-transparent to-blue-500/5">
              <div className="text-right mr-4">
                <h3 className="text-white font-black text-lg uppercase tracking-tight truncate max-w-[150px]">{matchState.homeTeam.name}</h3>
                <div className="flex gap-1 justify-end mt-1">
                  {matchState.events.filter(e => e.teamId === 'home' && e.type === 'YELLOW_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-yellow-400 rounded-sm" />)}
                  {matchState.events.filter(e => e.teamId === 'home' && e.type === 'RED_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-red-500 rounded-sm" />)}
                </div>
              </div>
              <div className="text-5xl font-black tabular-nums text-white drop-shadow-lg">{getGoals('home')}</div>
            </div>

            {/* Center: Clock & State Controls */}
            <div className="bg-slate-800/80 px-8 py-4 flex flex-col items-center justify-center border-x border-white/5 min-w-[240px]">
              <div className="flex items-center gap-2 mb-1">
                <span className="px-2 py-0.5 bg-blue-600 rounded-md text-[10px] font-black uppercase tracking-wider">{matchState.period}</span>
                <span className="text-slate-500 font-bold text-xs uppercase tracking-widest">Tempo Real</span>
              </div>
              <div className="text-5xl font-mono font-black tracking-tighter text-blue-400 drop-shadow-[0_0_10px_rgba(96,165,250,0.3)]">
                {matchState.currentTime < 10 ? `0${matchState.currentTime}` : matchState.currentTime}<span className="animate-pulse">:</span>00
              </div>

              <div className="flex items-center gap-3 mt-4">
                <button 
                  onClick={() => setMatchState(p => ({ ...p, isPaused: !p.isPaused, startTime: p.startTime || Date.now() }))}
                  className={`p-3 rounded-2xl transition-all shadow-lg active:scale-95 flex items-center justify-center ${
                    matchState.isPaused ? 'bg-emerald-500 hover:bg-emerald-400 text-white' : 'bg-red-500 hover:bg-red-400 text-white'
                  }`}
                >
                  {matchState.isPaused ? <Play size={24} fill="currentColor" /> : <Pause size={24} fill="currentColor" />}
                </button>
                <button 
                  onClick={nextPeriod}
                  className="p-3 bg-slate-700 hover:bg-slate-600 rounded-2xl text-slate-300 transition-all active:scale-95 group"
                  title="Próximo Período"
                >
                  <ChevronRight size={24} className="group-hover:translate-x-0.5 transition-transform" />
                </button>
                <button 
                  onClick={() => setShowResetConfirm(true)}
                  className="p-3 bg-slate-700 hover:bg-red-900/40 rounded-2xl text-slate-400 hover:text-red-400 transition-all active:scale-95"
                >
                  <Trash2 size={24} />
                </button>
              </div>
            </div>

            {/* Right: Away Score & Info */}
            <div className="flex-1 flex items-center justify-start px-6 py-4 bg-gradient-to-r from-transparent to-red-500/5">
              <div className="text-5xl font-black tabular-nums text-white drop-shadow-lg">{getGoals('away')}</div>
              <div className="text-left ml-4">
                <h3 className="text-white font-black text-lg uppercase tracking-tight truncate max-w-[150px]">{matchState.awayTeam.name}</h3>
                <div className="flex gap-1 justify-start mt-1">
                  {matchState.events.filter(e => e.teamId === 'away' && e.type === 'YELLOW_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-yellow-400 rounded-sm" />)}
                  {matchState.events.filter(e => e.teamId === 'away' && e.type === 'RED_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-red-500 rounded-sm" />)}
                </div>
              </div>
            </div>
          </div>

          {/* Bottom Quick Actions Bar */}
          <div className="bg-slate-950/50 border-t border-white/5 p-2 flex justify-between gap-1 overflow-x-auto no-scrollbar">
            <div className="flex gap-1">
              <button onClick={() => handleQuickAction('SHOT', 'home')} className="px-3 py-1.5 bg-slate-800 hover:bg-blue-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Chute</button>
              <button onClick={() => handleQuickAction('CORNER', 'home')} className="px-3 py-1.5 bg-slate-800 hover:bg-blue-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Escanteio</button>
              <button onClick={() => handleQuickAction('FOUL', 'home')} className="px-3 py-1.5 bg-slate-800 hover:bg-blue-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Falta</button>
            </div>
            <div className="flex gap-2">
               <button onClick={() => setShowUndoConfirm(true)} className="flex items-center gap-2 px-4 py-1.5 bg-slate-800 hover:bg-slate-700 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">
                <RotateCcw size={12} /> Desfazer
               </button>
            </div>
            <div className="flex gap-1">
              <button onClick={() => handleQuickAction('FOUL', 'away')} className="px-3 py-1.5 bg-slate-800 hover:bg-red-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Falta</button>
              <button onClick={() => handleQuickAction('CORNER', 'away')} className="px-3 py-1.5 bg-slate-800 hover:bg-red-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Escanteio</button>
              <button onClick={() => handleQuickAction('SHOT', 'away')} className="px-3 py-1.5 bg-slate-800 hover:bg-red-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Chute</button>
            </div>
          </div>
        </div>
      </div>

      {/* Main Tabs Selection */}
      <nav className="flex gap-2 mb-8 bg-slate-900/50 p-1.5 rounded-2xl border border-slate-700 self-center shadow-inner">
        {(['main', 'stats', 'report'] as const).map((tab) => (
          <button 
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`flex items-center gap-2 px-8 py-2.5 rounded-xl font-bold transition-all ${activeTab === tab ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-400 hover:text-white hover:bg-slate-800/40'}`}
          >
            {tab === 'main' ? 'Dashboard' : tab === 'stats' ? 'Dados' : 'Relatório'}
          </button>
        ))}
      </nav>

      {/* Content Area */}
      <main className="flex-1 mb-8 overflow-hidden rounded-[2.5rem]">
        {activeTab === 'main' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full">
            {/* Home Side */}
            <div className="lg:col-span-3 bg-slate-800/30 p-5 rounded-[2.5rem] border border-slate-700/50 flex flex-col gap-4 shadow-xl">
              <div className="flex items-center justify-between px-2">
                {isEditingNames.home ? (
                  <input autoFocus className="bg-slate-900 border border-blue-500 rounded-xl px-3 py-2 text-lg font-bold w-full" value={matchState.homeTeam.name} onBlur={() => setIsEditingNames(p => ({...p, home: false}))} onChange={(e) => setMatchState(p => ({...p, homeTeam: {...p.homeTeam, name: e.target.value}}))} />
                ) : (
                  <h2 className="text-xl font-black truncate flex items-center gap-2 group cursor-pointer" onClick={() => setIsEditingNames(p => ({...p, home: true}))}>
                    {matchState.homeTeam.name} <Edit2 size={14} className="opacity-0 group-hover:opacity-100 transition-opacity" />
                  </h2>
                )}
              </div>
              <PlayerList team={matchState.homeTeam} onPlayerClick={(p) => setCommandText(`Ação do jogador ${p.name}`)} />
              <div className="flex gap-2 mt-auto">
                <label className="flex-1 cursor-pointer flex items-center justify-center gap-2 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all">
                   <Camera size={14} /> Foto <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'home')} />
                </label>
                <button onClick={() => setShowTextInputModal({ show: true, teamId: 'home' })} className="flex-1 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all">Texto</button>
              </div>
            </div>

            {/* Field/List View */}
            <div className="lg:col-span-6 flex flex-col gap-4">
              <div className="flex justify-center gap-2">
                <button onClick={() => setViewMode('field')} className={`px-6 py-2 rounded-xl font-bold transition-all ${viewMode === 'field' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}>Tático</button>
                <button onClick={() => setViewMode('list')} className={`px-6 py-2 rounded-xl font-bold transition-all ${viewMode === 'list' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}>Lista</button>
              </div>
              {viewMode === 'field' ? <Field homeTeam={matchState.homeTeam} awayTeam={matchState.awayTeam} onPlayerClick={(p) => setCommandText(`Ação do ${p.name}`)} /> : 
              <div className="grid grid-cols-2 gap-4 h-[440px]"><PlayerList team={matchState.homeTeam} /><PlayerList team={matchState.awayTeam} /></div>}

              {/* Enhanced Event Log */}
              <div className="bg-slate-900/60 p-6 rounded-[2.5rem] border border-white/5 h-64 overflow-y-auto shadow-inner">
                <h4 className="text-[10px] font-black uppercase text-slate-500 mb-6 tracking-widest flex items-center gap-2"><History size={14} /> Histórico de Transmissão</h4>
                {matchState.events.length === 0 ? <p className="text-center text-slate-700 italic py-10">Aguardando lances da partida...</p> : 
                matchState.events.map(e => (
                  <div key={e.id} className="flex gap-4 py-4 border-b border-white/5 last:border-0 items-start hover:bg-white/5 transition-colors px-4 rounded-xl">
                    <span className="font-mono text-blue-400 font-black text-xs pt-0.5">{e.minute}'</span>
                    <div className="flex flex-col">
                      <span className="text-slate-200 font-bold text-sm">{e.description}</span>
                      <span className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">{e.type.replace('_', ' ')}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* Away Side */}
            <div className="lg:col-span-3 bg-slate-800/30 p-5 rounded-[2.5rem] border border-slate-700/50 flex flex-col gap-4 shadow-xl">
              <div className="flex items-center justify-between px-2 text-right">
                {isEditingNames.away ? (
                  <input autoFocus className="bg-slate-900 border border-red-500 rounded-xl px-3 py-2 text-lg font-bold w-full" value={matchState.awayTeam.name} onBlur={() => setIsEditingNames(p => ({...p, away: false}))} onChange={(e) => setMatchState(p => ({...p, awayTeam: {...p.awayTeam, name: e.target.value}}))} />
                ) : (
                  <h2 className="text-xl font-black truncate flex items-center justify-end gap-2 group cursor-pointer w-full" onClick={() => setIsEditingNames(p => ({...p, away: true}))}>
                    <Edit2 size={14} className="opacity-0 group-hover:opacity-100 transition-opacity" /> {matchState.awayTeam.name}
                  </h2>
                )}
              </div>
              <PlayerList team={matchState.awayTeam} onPlayerClick={(p) => setCommandText(`Ação do jogador ${p.name}`)} />
              <div className="flex gap-2 mt-auto">
                <label className="flex-1 cursor-pointer flex items-center justify-center gap-2 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all">
                   <Camera size={14} /> Foto <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'away')} />
                </label>
                <button onClick={() => setShowTextInputModal({ show: true, teamId: 'away' })} className="flex-1 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all">Texto</button>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'stats' && <MatchStats state={matchState} />}
        {activeTab === 'report' && (
          <div className="bg-slate-800/50 p-10 rounded-[3rem] border border-white/10 min-h-[60vh] flex flex-col shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-3xl font-black text-white">Relatório Narrativo</h2>
              <button onClick={createReport} disabled={isGeneratingReport} className="bg-blue-600 hover:bg-blue-500 px-10 py-4 rounded-2xl font-black flex items-center gap-3 transition-all active:scale-95">
                {isGeneratingReport ? <Loader2 size={24} className="animate-spin" /> : <FileText size={24} />} {isGeneratingReport ? 'Processando...' : 'Gerar Resumo IA'}
              </button>
            </div>
            <div className="flex-1 bg-slate-950/40 p-10 rounded-3xl border border-white/5 shadow-inner">
               {finalReport ? <div className="prose prose-invert max-w-none text-slate-300 text-lg leading-relaxed" dangerouslySetInnerHTML={{ __html: finalReport.replace(/\n/g, '<br/>') }} /> : 
               <div className="flex flex-col items-center justify-center h-full text-slate-600"><Trophy size={64} className="opacity-10 mb-6" /><p className="font-bold uppercase tracking-widest text-sm">Pronto para a narração final</p></div>}
            </div>
          </div>
        )}
      </main>

      {/* Smart Command Input */}
      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-full max-w-3xl px-4 z-[70]">
        <form onSubmit={handleCommand} className="bg-slate-900/90 p-3 rounded-full shadow-[0_30px_60px_rgba(0,0,0,0.8)] border border-white/10 flex items-center gap-3 backdrop-blur-3xl ring-8 ring-slate-900/40">
          <button type="button" onClick={() => setIsRecording(!isRecording)} className={`p-5 rounded-full transition-all active:scale-90 ${isRecording ? 'bg-red-600 animate-pulse' : 'bg-slate-800 hover:bg-slate-700'}`}>
            <Mic size={24} className="text-white" />
          </button>
          <div className="flex-1 relative">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-600" size={24} />
            <input type="text" placeholder="Descreva o lance agora... (ex: 'Cartão para o 10')" className="w-full bg-transparent py-4 pl-14 pr-6 font-bold text-xl placeholder:text-slate-600 text-white focus:outline-none" value={commandText} onChange={(e) => setCommandText(e.target.value)} />
          </div>
          <button type="submit" className="p-5 bg-blue-600 hover:bg-blue-500 rounded-full text-white font-black shadow-xl active:scale-90 transition-all"><ArrowRightLeft size={24} /></button>
        </form>
      </div>

      {/* Modals */}
      {showResetConfirm && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-800 p-12 rounded-[3rem] border border-white/10 max-w-md w-full text-center shadow-2xl">
            <div className="w-20 h-20 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-8 text-red-500"><Trash2 size={40} /></div>
            <h3 className="text-3xl font-black mb-4">Resetar Partida?</h3>
            <p className="text-slate-400 mb-10 leading-relaxed font-medium">Todos os dados, placar e histórico de lances serão apagados permanentemente. Deseja continuar?</p>
            <div className="flex gap-4">
              <button onClick={handleReset} className="flex-1 bg-red-600 hover:bg-red-500 py-5 rounded-[1.5rem] font-black transition-all shadow-xl active:scale-95">Resetar Tudo</button>
              <button onClick={() => setShowResetConfirm(false)} className="flex-1 bg-slate-700 hover:bg-slate-600 py-5 rounded-[1.5rem] font-black transition-all text-slate-300">Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {showUndoConfirm && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-800 p-10 rounded-[3rem] border border-white/10 max-w-sm w-full text-center">
            <h3 className="text-2xl font-black mb-8">Desfazer última ação?</h3>
            <div className="flex gap-4">
              <button onClick={handleUndo} className="flex-1 bg-red-600 py-4 rounded-2xl font-black active:scale-95 transition-all">Confirmar</button>
              <button onClick={() => setShowUndoConfirm(false)} className="flex-1 bg-slate-700 py-4 rounded-2xl font-black text-slate-300">Voltar</button>
            </div>
          </div>
        </div>
      )}

      {showTextInputModal.show && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-2xl z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-800 p-10 rounded-[3rem] border border-white/10 max-w-xl w-full">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-2xl font-black">Importar: {showTextInputModal.teamId === 'home' ? matchState.homeTeam.name : matchState.awayTeam.name}</h3>
              <button onClick={() => setShowTextInputModal({show: false, teamId: 'home'})} className="p-3 bg-slate-900 rounded-full"><X size={24} /></button>
            </div>
            <textarea className="w-full h-80 bg-slate-950 border border-white/5 rounded-[2rem] p-8 font-mono text-sm focus:ring-2 focus:ring-blue-500/50 outline-none resize-none text-blue-100 mb-8 shadow-inner" placeholder="Ex:&#10;1 Goleiro&#10;10 Atacante..." value={manualText} onChange={(e) => setManualText(e.target.value)} />
            <button onClick={handleManualTextInput} className="w-full bg-blue-600 hover:bg-blue-500 py-5 rounded-[1.5rem] font-black text-lg transition-all active:scale-95 shadow-xl shadow-blue-900/20">Processar Lista de Jogadores</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  LayoutGrid, 
  List, 
  Mic, 
  Camera, 
  RotateCcw, 
  Play, 
  Pause,
  FileText,
  BarChart2,
  Trophy,
  ArrowRightLeft,
  Search,
  Type as TypeIcon,
  X,
  Edit2,
  Loader2,
  Target,
  AlertCircle,
  Flag,
  ChevronRight,
  Trash2,
  // Added missing icon import
  History
} from 'lucide-react';
import { 
  MatchState, 
  Player, 
  Team, 
  MatchEvent, 
  EventType, 
  Position,
  MatchPeriod
} from './types';
import { 
  DEFAULT_HOME_TEAM, 
  DEFAULT_AWAY_TEAM, 
  STORAGE_KEY 
} from './constants';
import Field from './components/Field';
import PlayerList from './components/PlayerList';
import MatchStats from './components/MatchStats';
import { parsePlayersFromImage, processVoiceCommand, generateMatchReport } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'main' | 'stats' | 'report'>('main');
  const [viewMode, setViewMode] = useState<'field' | 'list'>('field');
  const [matchState, setMatchState] = useState<MatchState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : {
      homeTeam: DEFAULT_HOME_TEAM,
      awayTeam: DEFAULT_AWAY_TEAM,
      events: [],
      startTime: null,
      currentTime: 0,
      isPaused: true,
      period: 'PRE_MATCH'
    };
  });

  const [history, setHistory] = useState<MatchState[]>([]);
  const [isRecording, setIsRecording] = useState(false);
  const [commandText, setCommandText] = useState('');
  const [finalReport, setFinalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [showUndoConfirm, setShowUndoConfirm] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [isProcessingImage, setIsProcessingImage] = useState<false | 'home' | 'away'>(false);

  const [showTextInputModal, setShowTextInputModal] = useState<{show: boolean, teamId: 'home' | 'away'}>({ show: false, teamId: 'home' });
  const [manualText, setManualText] = useState('');
  const [isEditingNames, setIsEditingNames] = useState<{home: boolean, away: boolean}>({ home: false, away: false });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(matchState));
  }, [matchState]);

  useEffect(() => {
    let interval: any;
    if (!matchState.isPaused && matchState.period !== 'FINISHED' && matchState.period !== 'INTERVAL') {
      interval = setInterval(() => {
        setMatchState(prev => ({
          ...prev,
          currentTime: prev.currentTime + 1
        }));
      }, 60000);
    }
    return () => clearInterval(interval);
  }, [matchState.isPaused, matchState.period]);

  const saveToHistory = useCallback(() => {
    setHistory(prev => [...prev.slice(-10), JSON.parse(JSON.stringify(matchState))]);
  }, [matchState]);

  const addEvent = (eventData: Omit<MatchEvent, 'id' | 'timestamp' | 'minute'>) => {
    saveToHistory();
    const newEvent: MatchEvent = {
      ...eventData,
      id: Math.random().toString(36).substr(2, 9),
      minute: matchState.currentTime,
      timestamp: Date.now(),
    };

    setMatchState(prev => {
      const updateTeam = (team: Team) => ({
        ...team,
        players: team.players.map(p => 
          p.id === newEvent.playerId || p.id === newEvent.relatedPlayerId
          ? { ...p, events: [...p.events, newEvent] }
          : p
        )
      });

      return {
        ...prev,
        events: [newEvent, ...prev.events],
        homeTeam: updateTeam(prev.homeTeam),
        awayTeam: updateTeam(prev.awayTeam),
      };
    });
  };

  const handleUndo = () => {
    if (history.length > 0) {
      setMatchState(history[history.length - 1]);
      setHistory(prev => prev.slice(0, -1));
      setShowUndoConfirm(false);
    }
  };

  const handleReset = () => {
    const newState: MatchState = {
      homeTeam: { ...DEFAULT_HOME_TEAM, players: [] },
      awayTeam: { ...DEFAULT_AWAY_TEAM, players: [] },
      events: [],
      startTime: null,
      currentTime: 0,
      isPaused: true,
      period: 'PRE_MATCH'
    };
    setMatchState(newState);
    setHistory([]);
    setFinalReport('');
    setShowResetConfirm(false);
  };

  const nextPeriod = () => {
    const periods: MatchPeriod[] = ['PRE_MATCH', '1T', 'INTERVAL', '2T', 'FINISHED'];
    const currentIndex = periods.indexOf(matchState.period);
    if (currentIndex < periods.length - 1) {
      const newPeriod = periods[currentIndex + 1];
      saveToHistory();
      setMatchState(prev => ({
        ...prev,
        period: newPeriod,
        isPaused: newPeriod === 'INTERVAL' || newPeriod === 'FINISHED' || newPeriod === 'PRE_MATCH'
      }));
      addEvent({
        type: 'PERIOD_START',
        teamId: 'none',
        description: `Início: ${newPeriod}`
      });
    }
  };

  const handleQuickAction = (type: EventType, teamId: 'home' | 'away') => {
    const team = matchState[teamId === 'home' ? 'homeTeam' : 'awayTeam'];
    addEvent({
      type,
      teamId,
      description: `${type.replace('_', ' ')} para ${team.name}`
    });
  };

  const handleCommand = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!commandText.trim()) return;

    try {
      const result = await processVoiceCommand(commandText, `Match minute ${matchState.currentTime}. Home: ${matchState.homeTeam.name}, Away: ${matchState.awayTeam.name}`);
      if (result.type !== 'INVALID') {
        const teamId = result.team === 'home' ? 'homeTeam' : 'awayTeam';
        const team = matchState[teamId];
        const player = team.players.find(p => p.number === result.playerNumber);
        addEvent({
          type: result.type as EventType,
          teamId: result.team as 'home' | 'away',
          playerId: player?.id,
          description: result.description
        });
        setCommandText('');
      } else {
        alert("Comando não reconhecido.");
      }
    } catch (error) { console.error(error); }
  };

  const processPlayerList = (list: any[], teamId: 'home' | 'away') => {
    return list.map((p: any, i: number) => {
      const names = p.name.trim().split(' ');
      let shortName = names.length > 1 ? names[0] : p.name;
      return {
        id: Math.random().toString(36).substr(2, 9),
        fullName: p.name,
        name: shortName,
        number: p.number || (i + 1),
        teamId,
        isStarter: i < 11,
        position: (i === 0 ? 'GK' : i < 5 ? 'DF' : i < 9 ? 'MF' : 'FW') as Position,
        events: []
      } as Player;
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, teamId: 'home' | 'away') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingImage(teamId);
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result?.toString().split(',')[1];
      if (base64) {
        try {
          const data = await parsePlayersFromImage(base64);
          setMatchState(prev => ({
            ...prev,
            [teamId === 'home' ? 'homeTeam' : 'awayTeam']: { 
              ...prev[teamId === 'home' ? 'homeTeam' : 'awayTeam'], 
              name: data.teamName || prev[teamId === 'home' ? 'homeTeam' : 'awayTeam'].name,
              players: processPlayerList(data.players || [], teamId) 
            }
          }));
        } catch (error) { alert("Erro ao processar imagem."); } finally { setIsProcessingImage(false); e.target.value = ''; }
      }
    };
    reader.readAsDataURL(file);
  };

  const handleManualTextInput = () => {
    const lines = manualText.split('\n');
    const players = lines.filter(l => l.trim()).map(line => {
      const numMatch = line.match(/\d+/);
      const name = line.replace(/\d+/g, '').trim();
      return { name, number: numMatch ? parseInt(numMatch[0]) : 0 };
    });
    const teamKey = showTextInputModal.teamId === 'home' ? 'homeTeam' : 'awayTeam';
    setMatchState(prev => ({
      ...prev,
      [teamKey]: { ...prev[teamKey], players: processPlayerList(players, showTextInputModal.teamId) }
    }));
    setManualText('');
    setShowTextInputModal({ show: false, teamId: 'home' });
  };

  const getGoals = (teamId: 'home' | 'away') => 
    matchState.events.filter(e => e.teamId === teamId && e.type === 'GOAL').length;

  // Added missing createReport function to resolve the error on line 438
  const createReport = async () => {
    if (matchState.events.length === 0) {
      setFinalReport("Nenhum lance registrado para gerar o relatório.");
      return;
    }
    setIsGeneratingReport(true);
    try {
      const eventsSummary = matchState.events
        .map(e => `[${e.minute}'] ${e.description}`)
        .reverse() // Sort chronologically for better AI context
        .join('\n');

      const context = `Contexto: Partida entre ${matchState.homeTeam.name} e ${matchState.awayTeam.name}. Placar Final: ${getGoals('home')}x${getGoals('away')}.`;
      const report = await generateMatchReport(`${context}\n\nLances do jogo:\n${eventsSummary}`);
      setFinalReport(report);
    } catch (error) {
      console.error("Failed to generate report", error);
      setFinalReport("Erro ao gerar o relatório narrativo. Verifique sua conexão e tente novamente.");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  return (
