export default App;

export type Position = 'GK' | 'DF' | 'MF' | 'FW';

export interface Player {
  id: string;
  name: string;
  fullName: string;
  number: number;
  position: Position;
  teamId: 'home' | 'away';
  isStarter: boolean;
  events: MatchEvent[];
  // Tactical coordinates (0-100 scale)
  x: number;
  y: number;
}

export interface Team {
  id: 'home' | 'away';
  name: string;
  color: string;
  players: Player[];
}

export type EventType = 'GOAL' | 'YELLOW_CARD' | 'RED_CARD' | 'SUBSTITUTION' | 'SHOT' | 'FOUL' | 'CORNER' | 'PERIOD_START' | 'PERIOD_END';

export type MatchPeriod = 'PRE_MATCH' | '1T' | 'INTERVAL' | '2T' | 'ET' | 'FINISHED';

export interface MatchEvent {
  id: string;
  type: EventType;
  minute: number;
  playerId?: string;
  relatedPlayerId?: string; // e.g., assistant or sub-in
  teamId: 'home' | 'away' | 'none';
  description: string;
  timestamp: number;
}

export interface MatchState {
  homeTeam: Team;
  awayTeam: Team;
  events: MatchEvent[];
  startTime: number | null;
  currentTime: number; // match minute
  isPaused: boolean;
  period: MatchPeriod;
}

export interface AICommandResponse {
  type: EventType | 'INVALID';
  team?: 'home' | 'away';
  playerNumber?: number;
  playerInNumber?: number;
  playerOutNumber?: number;
  description: string;
}

import React, { useRef, useState, useEffect } from 'react';
import { Team, Player } from '../types';

interface FieldProps {
  homeTeam: Team;
  awayTeam: Team;
  onPlayerClick: (player: Player) => void;
  onPlayerMove: (teamId: 'home' | 'away', playerId: string, x: number, y: number) => void;
}

const Field: React.FC<FieldProps> = ({ homeTeam, awayTeam, onPlayerClick, onPlayerMove }) => {
  const fieldRef = useRef<HTMLDivElement>(null);
  const [activePlayer, setActivePlayer] = useState<{ teamId: 'home' | 'away', playerId: string } | null>(null);

  const handleMouseDown = (e: React.MouseEvent | React.TouchEvent, teamId: 'home' | 'away', playerId: string) => {
    // Prevent scrolling when touching
    if (e.type === 'touchstart') {
      // e.preventDefault();
    }
    setActivePlayer({ teamId, playerId });
  };

  const handleMouseMove = (e: MouseEvent | TouchEvent) => {
    if (!activePlayer || !fieldRef.current) return;

    const rect = fieldRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    // Calculate percentage relative to field dimensions
    let x = ((clientX - rect.left) / rect.width) * 100;
    let y = ((clientY - rect.top) / rect.height) * 100;

    // Constrain within field
    x = Math.max(2, Math.min(98, x));
    y = Math.max(2, Math.min(98, y));

    onPlayerMove(activePlayer.teamId, activePlayer.playerId, x, y);
  };

  const handleMouseUp = () => {
    setActivePlayer(null);
  };

  useEffect(() => {
    if (activePlayer) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
      window.addEventListener('touchmove', handleMouseMove, { passive: false });
      window.addEventListener('touchend', handleMouseUp);
    }
    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
      window.removeEventListener('touchmove', handleMouseMove);
      window.removeEventListener('touchend', handleMouseUp);
    };
  }, [activePlayer]);

  const renderPlayers = (team: Team) => {
    return team.players.filter(p => p.isStarter).map((player) => {
      const isDragging = activePlayer?.playerId === player.id;
      return (
        <div
          key={player.id}
          className={`absolute -translate-x-1/2 -translate-y-1/2 transition-shadow cursor-move select-none z-10 ${isDragging ? 'z-50 scale-125' : ''}`}
          style={{ top: `${player.y}%`, left: `${player.x}%` }}
          onMouseDown={(e) => handleMouseDown(e, team.id, player.id)}
          onTouchStart={(e) => handleMouseDown(e, team.id, player.id)}
        >
          <div className="group relative flex flex-col items-center">
             <button
              onClick={() => !isDragging && onPlayerClick(player)}
              className={`w-10 h-10 md:w-12 md:h-12 rounded-full flex items-center justify-center border-2 border-white shadow-xl text-white font-black text-sm md:text-base transition-all ${isDragging ? 'ring-4 ring-white/50 ring-offset-2 ring-offset-slate-900' : ''}`}
              style={{ backgroundColor: team.color }}
            >
              {player.number}
            </button>
            <div className={`mt-1 bg-slate-900/90 text-white px-2 py-0.5 rounded text-[10px] md:text-xs font-black whitespace-nowrap shadow-md border border-white/10 ${isDragging ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}>
              {player.name}
            </div>
          </div>
        </div>
      );
    });
  };

  return (
    <div 
      ref={fieldRef}
      className="relative w-full aspect-[4/3] bg-emerald-700 rounded-3xl overflow-hidden shadow-[0_20px_50px_rgba(0,0,0,0.5)] border-4 border-emerald-800/50 select-none"
    >
      {/* Turf Pattern */}
      <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: 'repeating-linear-gradient(90deg, transparent, transparent 10%, rgba(0,0,0,0.2) 10%, rgba(0,0,0,0.2) 20%)' }}></div>

      {/* Field markings */}
      <div className="absolute inset-0 border-2 border-white/30 m-6 rounded-sm"></div>
      <div className="absolute inset-y-0 left-1/2 w-0.5 bg-white/30"></div>
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-32 h-32 border-2 border-white/30 rounded-full"></div>

      {/* Penalty areas */}
      <div className="absolute top-1/2 left-0 -translate-y-1/2 w-28 h-56 border-2 border-white/30 border-l-0 rounded-r-lg"></div>
      <div className="absolute top-1/2 right-0 -translate-y-1/2 w-28 h-56 border-2 border-white/30 border-r-0 rounded-l-lg"></div>

      {/* Penalty Spots */}
      <div className="absolute top-1/2 left-[14%] -translate-x-1/2 -translate-y-1/2 w-2 h-2 bg-white/50 rounded-full"></div>
      <div className="absolute top-1/2 right-[14%] translate-x-1/2 -translate-y-1/2 w-2 h-2 bg-white/50 rounded-full"></div>

      {renderPlayers(homeTeam)}
      {renderPlayers(awayTeam)}

      {/* Helper text overlay */}
      <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-black/40 backdrop-blur-md px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest text-white/50 pointer-events-none">
        Arraste os jogadores para ajustar a tática
      </div>
    </div>
  );
};

export default Field;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  LayoutGrid, 
  List, 
  Mic, 
  Camera, 
  RotateCcw, 
  Play, 
  Pause,
  FileText,
  BarChart2,
  Trophy,
  ArrowRightLeft,
  Search,
  Type as TypeIcon,
  X,
  Edit2,
  Loader2,
  Target,
  AlertCircle,
  Flag,
  ChevronRight,
  Trash2,
  History
} from 'lucide-react';
import { 
  MatchState, 
  Player, 
  Team, 
  MatchEvent, 
  EventType, 
  Position,
  MatchPeriod
} from './types';
import { 
  DEFAULT_HOME_TEAM, 
  DEFAULT_AWAY_TEAM, 
  STORAGE_KEY 
} from './constants';
import Field from './components/Field';
import PlayerList from './components/PlayerList';
import MatchStats from './components/MatchStats';
import { parsePlayersFromImage, processVoiceCommand, generateMatchReport } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'main' | 'stats' | 'report'>('main');
  const [viewMode, setViewMode] = useState<'field' | 'list'>('field');
  const [matchState, setMatchState] = useState<MatchState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : {
      homeTeam: DEFAULT_HOME_TEAM,
      awayTeam: DEFAULT_AWAY_TEAM,
      events: [],
      startTime: null,
      currentTime: 0,
      isPaused: true,
      period: 'PRE_MATCH'
    };
  });

  const [history, setHistory] = useState<MatchState[]>([]);
  const [isRecording, setIsRecording] = useState(false);
  const [commandText, setCommandText] = useState('');
  const [finalReport, setFinalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [showUndoConfirm, setShowUndoConfirm] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [isProcessingImage, setIsProcessingImage] = useState<false | 'home' | 'away'>(false);

  const [showTextInputModal, setShowTextInputModal] = useState<{show: boolean, teamId: 'home' | 'away'}>({ show: false, teamId: 'home' });
  const [manualText, setManualText] = useState('');
  const [isEditingNames, setIsEditingNames] = useState<{home: boolean, away: boolean}>({ home: false, away: false });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(matchState));
  }, [matchState]);

  useEffect(() => {
    let interval: any;
    if (!matchState.isPaused && matchState.period !== 'FINISHED' && matchState.period !== 'INTERVAL') {
      interval = setInterval(() => {
        setMatchState(prev => ({
          ...prev,
          currentTime: prev.currentTime + 1
        }));
      }, 60000);
    }
    return () => clearInterval(interval);
  }, [matchState.isPaused, matchState.period]);

  const saveToHistory = useCallback(() => {
    setHistory(prev => [...prev.slice(-10), JSON.parse(JSON.stringify(matchState))]);
  }, [matchState]);

  const addEvent = (eventData: Omit<MatchEvent, 'id' | 'timestamp' | 'minute'>) => {
    saveToHistory();
    const newEvent: MatchEvent = {
      ...eventData,
      id: Math.random().toString(36).substr(2, 9),
      minute: matchState.currentTime,
      timestamp: Date.now(),
    };

    setMatchState(prev => {
      const updateTeam = (team: Team) => ({
        ...team,
        players: team.players.map(p => 
          p.id === newEvent.playerId || p.id === newEvent.relatedPlayerId
          ? { ...p, events: [...p.events, newEvent] }
          : p
        )
      });

      return {
        ...prev,
        events: [newEvent, ...prev.events],
        homeTeam: updateTeam(prev.homeTeam),
        awayTeam: updateTeam(prev.awayTeam),
      };
    });
  };

  const handleUndo = () => {
    if (history.length > 0) {
      setMatchState(history[history.length - 1]);
      setHistory(prev => prev.slice(0, -1));
      setShowUndoConfirm(false);
    }
  };

  const handleReset = () => {
    const newState: MatchState = {
      homeTeam: { ...DEFAULT_HOME_TEAM, players: [] },
      awayTeam: { ...DEFAULT_AWAY_TEAM, players: [] },
      events: [],
      startTime: null,
      currentTime: 0,
      isPaused: true,
      period: 'PRE_MATCH'
    };
    setMatchState(newState);
    setHistory([]);
    setFinalReport('');
    setShowResetConfirm(false);
  };

  const nextPeriod = () => {
    const periods: MatchPeriod[] = ['PRE_MATCH', '1T', 'INTERVAL', '2T', 'FINISHED'];
    const currentIndex = periods.indexOf(matchState.period);
    if (currentIndex < periods.length - 1) {
      const newPeriod = periods[currentIndex + 1];
      saveToHistory();
      setMatchState(prev => ({
        ...prev,
        period: newPeriod,
        isPaused: newPeriod === 'INTERVAL' || newPeriod === 'FINISHED' || newPeriod === 'PRE_MATCH'
      }));
      addEvent({
        type: 'PERIOD_START',
        teamId: 'none',
        description: `Início: ${newPeriod}`
      });
    }
  };

  const handleQuickAction = (type: EventType, teamId: 'home' | 'away') => {
    const team = matchState[teamId === 'home' ? 'homeTeam' : 'awayTeam'];
    addEvent({
      type,
      teamId,
      description: `${type.replace('_', ' ')} para ${team.name}`
    });
  };

  const handleCommand = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!commandText.trim()) return;

    try {
      const result = await processVoiceCommand(commandText, `Match minute ${matchState.currentTime}. Home: ${matchState.homeTeam.name}, Away: ${matchState.awayTeam.name}`);
      if (result.type !== 'INVALID') {
        const teamId = result.team === 'home' ? 'homeTeam' : 'awayTeam';
        const team = matchState[teamId];
        const player = team.players.find(p => p.number === result.playerNumber);
        addEvent({
          type: result.type as EventType,
          teamId: result.team as 'home' | 'away',
          playerId: player?.id,
          description: result.description
        });
        setCommandText('');
      } else {
        alert("Comando não reconhecido.");
      }
    } catch (error) { console.error(error); }
  };

  const getPositionCoordinates = (index: number, teamId: 'home' | 'away') => {
    const isHome = teamId === 'home';
    const baseRows = [
      { y: 50, x: isHome ? 8 : 92 }, // GK
      { y: 20, x: isHome ? 25 : 75 }, { y: 40, x: isHome ? 25 : 75 }, 
      { y: 60, x: isHome ? 25 : 75 }, { y: 80, x: isHome ? 25 : 75 }, // DF
      { y: 20, x: isHome ? 45 : 55 }, { y: 40, x: isHome ? 45 : 55 },
      { y: 60, x: isHome ? 45 : 55 }, { y: 80, x: isHome ? 45 : 55 }, // MF
      { y: 35, x: isHome ? 65 : 35 }, { y: 65, x: isHome ? 65 : 35 }, // FW
    ];
    return baseRows[index] || { y: 50, x: 50 };
  };

  const processPlayerList = (list: any[], teamId: 'home' | 'away') => {
    return list.map((p: any, i: number) => {
      const names = p.name.trim().split(' ');
      let shortName = names.length > 1 ? names[0] : p.name;
      const coords = getPositionCoordinates(i, teamId);
      return {
        id: Math.random().toString(36).substr(2, 9),
        fullName: p.name,
        name: shortName,
        number: p.number || (i + 1),
        teamId,
        isStarter: i < 11,
        position: (i === 0 ? 'GK' : i < 5 ? 'DF' : i < 9 ? 'MF' : 'FW') as Position,
        events: [],
        x: coords.x,
        y: coords.y
      } as Player;
    });
  };

  const handlePlayerMove = (teamId: 'home' | 'away', playerId: string, x: number, y: number) => {
    setMatchState(prev => {
      const targetTeamKey = teamId === 'home' ? 'homeTeam' : 'awayTeam';
      return {
        ...prev,
        [targetTeamKey]: {
          ...prev[targetTeamKey],
          players: prev[targetTeamKey].players.map(p => 
            p.id === playerId ? { ...p, x, y } : p
          )
        }
      };
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, teamId: 'home' | 'away') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingImage(teamId);
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result?.toString().split(',')[1];
      if (base64) {
        try {
          const data = await parsePlayersFromImage(base64);
          setMatchState(prev => ({
            ...prev,
            [teamId === 'home' ? 'homeTeam' : 'awayTeam']: { 
              ...prev[teamId === 'home' ? 'homeTeam' : 'awayTeam'], 
              name: data.teamName || prev[teamId === 'home' ? 'homeTeam' : 'awayTeam'].name,
              players: processPlayerList(data.players || [], teamId) 
            }
          }));
        } catch (error) { alert("Erro ao processar imagem."); } finally { setIsProcessingImage(false); e.target.value = ''; }
      }
    };
    reader.readAsDataURL(file);
  };

  const handleManualTextInput = () => {
    const lines = manualText.split('\n');
    const players = lines.filter(l => l.trim()).map(line => {
      const numMatch = line.match(/\d+/);
      const name = line.replace(/\d+/g, '').trim();
      return { name, number: numMatch ? parseInt(numMatch[0]) : 0 };
    });
    const teamKey = showTextInputModal.teamId === 'home' ? 'homeTeam' : 'awayTeam';
    setMatchState(prev => ({
      ...prev,
      [teamKey]: { ...prev[teamKey], players: processPlayerList(players, showTextInputModal.teamId) }
    }));
    setManualText('');
    setShowTextInputModal({ show: false, teamId: 'home' });
  };

  const getGoals = (teamId: 'home' | 'away') => 
    matchState.events.filter(e => e.teamId === teamId && e.type === 'GOAL').length;

  const createReport = async () => {
    if (matchState.events.length === 0) {
      setFinalReport("Nenhum lance registrado para gerar o relatório.");
      return;
    }
    setIsGeneratingReport(true);
    try {
      const eventsSummary = matchState.events
        .map(e => `[${e.minute}'] ${e.description}`)
        .reverse()
        .join('\n');

      const context = `Contexto: Partida entre ${matchState.homeTeam.name} e ${matchState.awayTeam.name}. Placar Final: ${getGoals('home')}x${getGoals('away')}.`;
      const report = await generateMatchReport(`${context}\n\nLances do jogo:\n${eventsSummary}`);
      setFinalReport(report);
    } catch (error) {
      setFinalReport("Erro ao gerar o relatório narrativo.");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col max-w-7xl mx-auto p-4 md:p-6 pb-32">
      {/* PREMIUM MATCH CONTROL BAR */}
      <div className="sticky top-4 z-[60] mb-8">
        <div className="bg-slate-900/95 border border-white/10 rounded-[2rem] shadow-[0_20px_50px_rgba(0,0,0,0.5)] backdrop-blur-2xl overflow-hidden ring-1 ring-white/5">
          <div className="flex flex-col md:flex-row items-stretch">
            {/* Left: Home Score */}
            <div className="flex-1 flex items-center justify-end px-6 py-4 bg-gradient-to-l from-transparent to-blue-500/5">
              <div className="text-right mr-4">
                <h3 className="text-white font-black text-lg uppercase tracking-tight truncate max-w-[150px]">{matchState.homeTeam.name}</h3>
                <div className="flex gap-1 justify-end mt-1">
                  {matchState.events.filter(e => e.teamId === 'home' && e.type === 'YELLOW_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-yellow-400 rounded-sm" />)}
                  {matchState.events.filter(e => e.teamId === 'home' && e.type === 'RED_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-red-500 rounded-sm" />)}
                </div>
              </div>
              <div className="text-5xl font-black tabular-nums text-white drop-shadow-lg">{getGoals('home')}</div>
            </div>

            {/* Center: Clock */}
            <div className="bg-slate-800/80 px-8 py-4 flex flex-col items-center justify-center border-x border-white/5 min-w-[240px]">
              <div className="flex items-center gap-2 mb-1">
                <span className="px-2 py-0.5 bg-blue-600 rounded-md text-[10px] font-black uppercase tracking-wider">{matchState.period}</span>
                <span className="text-slate-500 font-bold text-xs uppercase tracking-widest">Tempo Real</span>
              </div>
              <div className="text-5xl font-mono font-black tracking-tighter text-blue-400 drop-shadow-[0_0_10px_rgba(96,165,250,0.3)]">
                {matchState.currentTime < 10 ? `0${matchState.currentTime}` : matchState.currentTime}<span className="animate-pulse">:</span>00
              </div>
              <div className="flex items-center gap-3 mt-4">
                <button onClick={() => setMatchState(p => ({ ...p, isPaused: !p.isPaused, startTime: p.startTime || Date.now() }))} className={`p-3 rounded-2xl transition-all shadow-lg active:scale-95 flex items-center justify-center ${matchState.isPaused ? 'bg-emerald-500 hover:bg-emerald-400 text-white' : 'bg-red-500 hover:bg-red-400 text-white'}`}>
                  {matchState.isPaused ? <Play size={24} fill="currentColor" /> : <Pause size={24} fill="currentColor" />}
                </button>
                <button onClick={nextPeriod} className="p-3 bg-slate-700 hover:bg-slate-600 rounded-2xl text-slate-300 transition-all active:scale-95 group"><ChevronRight size={24} /></button>
                <button onClick={() => setShowResetConfirm(true)} className="p-3 bg-slate-700 hover:bg-red-900/40 rounded-2xl text-slate-400 hover:text-red-400 transition-all active:scale-95"><Trash2 size={24} /></button>
              </div>
            </div>

            {/* Right: Away Score */}
            <div className="flex-1 flex items-center justify-start px-6 py-4 bg-gradient-to-r from-transparent to-red-500/5">
              <div className="text-5xl font-black tabular-nums text-white drop-shadow-lg">{getGoals('away')}</div>
              <div className="text-left ml-4">
                <h3 className="text-white font-black text-lg uppercase tracking-tight truncate max-w-[150px]">{matchState.awayTeam.name}</h3>
                <div className="flex gap-1 justify-start mt-1">
                  {matchState.events.filter(e => e.teamId === 'away' && e.type === 'YELLOW_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-yellow-400 rounded-sm" />)}
                  {matchState.events.filter(e => e.teamId === 'away' && e.type === 'RED_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-red-500 rounded-sm" />)}
                </div>
              </div>
            </div>
          </div>

          <div className="bg-slate-950/50 border-t border-white/5 p-2 flex justify-between gap-1 overflow-x-auto no-scrollbar">
            <div className="flex gap-1">
              <button onClick={() => handleQuickAction('SHOT', 'home')} className="px-3 py-1.5 bg-slate-800 hover:bg-blue-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Chute</button>
              <button onClick={() => handleQuickAction('CORNER', 'home')} className="px-3 py-1.5 bg-slate-800 hover:bg-blue-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Escanteio</button>
              <button onClick={() => handleQuickAction('FOUL', 'home')} className="px-3 py-1.5 bg-slate-800 hover:bg-blue-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Falta</button>
            </div>
            <div className="flex gap-2">
               <button onClick={() => setShowUndoConfirm(true)} className="flex items-center gap-2 px-4 py-1.5 bg-slate-800 hover:bg-slate-700 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all"><RotateCcw size={12} /> Desfazer</button>
            </div>
            <div className="flex gap-1">
              <button onClick={() => handleQuickAction('FOUL', 'away')} className="px-3 py-1.5 bg-slate-800 hover:bg-red-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Falta</button>
              <button onClick={() => handleQuickAction('CORNER', 'away')} className="px-3 py-1.5 bg-slate-800 hover:bg-red-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Escanteio</button>
              <button onClick={() => handleQuickAction('SHOT', 'away')} className="px-3 py-1.5 bg-slate-800 hover:bg-red-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Chute</button>
            </div>
          </div>
        </div>
      </div>

      <nav className="flex gap-2 mb-8 bg-slate-900/50 p-1.5 rounded-2xl border border-slate-700 self-center shadow-inner">
        {(['main', 'stats', 'report'] as const).map((tab) => (
          <button key={tab} onClick={() => setActiveTab(tab)} className={`flex items-center gap-2 px-8 py-2.5 rounded-xl font-bold transition-all ${activeTab === tab ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-400 hover:text-white hover:bg-slate-800/40'}`}>
            {tab === 'main' ? 'Dashboard' : tab === 'stats' ? 'Dados' : 'Relatório'}
          </button>
        ))}
      </nav>

      <main className="flex-1 mb-8 overflow-hidden rounded-[2.5rem]">
        {activeTab === 'main' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full">
            <div className="lg:col-span-3 bg-slate-800/30 p-5 rounded-[2.5rem] border border-slate-700/50 flex flex-col gap-4 shadow-xl">
              <div className="flex items-center justify-between px-2">
                {isEditingNames.home ? (
                  <input autoFocus className="bg-slate-900 border border-blue-500 rounded-xl px-3 py-2 text-lg font-bold w-full" value={matchState.homeTeam.name} onBlur={() => setIsEditingNames(p => ({...p, home: false}))} onChange={(e) => setMatchState(p => ({...p, homeTeam: {...p.homeTeam, name: e.target.value}}))} />
                ) : (
                  <h2 className="text-xl font-black truncate flex items-center gap-2 group cursor-pointer" onClick={() => setIsEditingNames(p => ({...p, home: true}))}>{matchState.homeTeam.name} <Edit2 size={14} className="opacity-0 group-hover:opacity-100 transition-opacity" /></h2>
                )}
              </div>
              <PlayerList team={matchState.homeTeam} onPlayerClick={(p) => setCommandText(`Ação do jogador ${p.name}`)} />
              <div className="flex gap-2 mt-auto">
                <label className="flex-1 cursor-pointer flex items-center justify-center gap-2 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all"><Camera size={14} /> Foto <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'home')} /></label>
                <button onClick={() => setShowTextInputModal({ show: true, teamId: 'home' })} className="flex-1 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all">Texto</button>
              </div>
            </div>

            <div className="lg:col-span-6 flex flex-col gap-4">
              <div className="flex justify-center gap-2">
                <button onClick={() => setViewMode('field')} className={`px-6 py-2 rounded-xl font-bold transition-all ${viewMode === 'field' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}>Tático</button>
                <button onClick={() => setViewMode('list')} className={`px-6 py-2 rounded-xl font-bold transition-all ${viewMode === 'list' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}>Lista</button>
              </div>
              {viewMode === 'field' ? <Field homeTeam={matchState.homeTeam} awayTeam={matchState.awayTeam} onPlayerClick={(p) => setCommandText(`Ação do ${p.name}`)} onPlayerMove={handlePlayerMove} /> : 
              <div className="grid grid-cols-2 gap-4 h-[440px]"><PlayerList team={matchState.homeTeam} /><PlayerList team={matchState.awayTeam} /></div>}

              <div className="bg-slate-900/60 p-6 rounded-[2.5rem] border border-white/5 h-64 overflow-y-auto shadow-inner">
                <h4 className="text-[10px] font-black uppercase text-slate-500 mb-6 tracking-widest flex items-center gap-2"><History size={14} /> Histórico</h4>
                {matchState.events.length === 0 ? <p className="text-center text-slate-700 italic py-10">Aguardando lances...</p> : 
                matchState.events.map(e => (
                  <div key={e.id} className="flex gap-4 py-4 border-b border-white/5 last:border-0 items-start hover:bg-white/5 transition-colors px-4 rounded-xl">
                    <span className="font-mono text-blue-400 font-black text-xs pt-0.5">{e.minute}'</span>
                    <div className="flex flex-col"><span className="text-slate-200 font-bold text-sm">{e.description}</span><span className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">{e.type.replace('_', ' ')}</span></div>
                  </div>
                ))}
              </div>
            </div>

            <div className="lg:col-span-3 bg-slate-800/30 p-5 rounded-[2.5rem] border border-slate-700/50 flex flex-col gap-4 shadow-xl">
              <div className="flex items-center justify-between px-2 text-right">
                {isEditingNames.away ? (
                  <input autoFocus className="bg-slate-900 border border-red-500 rounded-xl px-3 py-2 text-lg font-bold w-full" value={matchState.awayTeam.name} onBlur={() => setIsEditingNames(p => ({...p, away: false}))} onChange={(e) => setMatchState(p => ({...p, awayTeam: {...p.awayTeam, name: e.target.value}}))} />
                ) : (
                  <h2 className="text-xl font-black truncate flex items-center justify-end gap-2 group cursor-pointer w-full" onClick={() => setIsEditingNames(p => ({...p, away: true}))}><Edit2 size={14} className="opacity-0 group-hover:opacity-100 transition-opacity" /> {matchState.awayTeam.name}</h2>
                )}
              </div>
              <PlayerList team={matchState.awayTeam} onPlayerClick={(p) => setCommandText(`Ação do jogador ${p.name}`)} />
              <div className="flex gap-2 mt-auto">
                <label className="flex-1 cursor-pointer flex items-center justify-center gap-2 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all"><Camera size={14} /> Foto <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'away')} /></label>
                <button onClick={() => setShowTextInputModal({ show: true, teamId: 'away' })} className="flex-1 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all">Texto</button>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'stats' && <MatchStats state={matchState} />}
        {activeTab === 'report' && (
          <div className="bg-slate-800/50 p-10 rounded-[3rem] border border-white/10 min-h-[60vh] flex flex-col shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-3xl font-black text-white">Relatório Narrativo</h2>
              <button onClick={createReport} disabled={isGeneratingReport} className="bg-blue-600 hover:bg-blue-500 px-10 py-4 rounded-2xl font-black flex items-center gap-3 transition-all active:scale-95">
                {isGeneratingReport ? <Loader2 size={24} className="animate-spin" /> : <FileText size={24} />} {isGeneratingReport ? 'Processando...' : 'Gerar Resumo IA'}
              </button>
            </div>
            <div className="flex-1 bg-slate-950/40 p-10 rounded-3xl border border-white/5 shadow-inner">
               {finalReport ? <div className="prose prose-invert max-w-none text-slate-300 text-lg leading-relaxed" dangerouslySetInnerHTML={{ __html: finalReport.replace(/\n/g, '<br/>') }} /> : 
               <div className="flex flex-col items-center justify-center h-full text-slate-600"><Trophy size={64} className="opacity-10 mb-6" /><p className="font-bold uppercase tracking-widest text-sm">Pronto para a narração final</p></div>}
            </div>
          </div>
        )}
      </main>

      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-full max-w-3xl px-4 z-[70]">
        <form onSubmit={handleCommand} className="bg-slate-900/90 p-3 rounded-full shadow-[0_30px_60px_rgba(0,0,0,0.8)] border border-white/10 flex items-center gap-3 backdrop-blur-3xl ring-8 ring-slate-900/40">
          <button type="button" onClick={() => setIsRecording(!isRecording)} className={`p-5 rounded-full transition-all active:scale-90 ${isRecording ? 'bg-red-600 animate-pulse' : 'bg-slate-800 hover:bg-slate-700'}`}>
            <Mic size={24} className="text-white" />
          </button>
          <div className="flex-1 relative">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-600" size={24} />
            <input type="text" placeholder="Descreva o lance... (ex: 'Cartão para o 10')" className="w-full bg-transparent py-4 pl-14 pr-6 font-bold text-xl placeholder:text-slate-600 text-white focus:outline-none" value={commandText} onChange={(e) => setCommandText(e.target.value)} />
          </div>
          <button type="submit" className="p-5 bg-blue-600 hover:bg-blue-500 rounded-full text-white font-black shadow-xl active:scale-90 transition-all"><ArrowRightLeft size={24} /></button>
        </form>
      </div>

      {showResetConfirm && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-800 p-12 rounded-[3rem] border border-white/10 max-w-md w-full text-center shadow-2xl">
            <div className="w-20 h-20 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-8 text-red-500"><Trash2 size={40} /></div>
            <h3 className="text-3xl font-black mb-4">Resetar Partida?</h3>
            <div className="flex gap-4">
              <button onClick={handleReset} className="flex-1 bg-red-600 hover:bg-red-500 py-5 rounded-[1.5rem] font-black transition-all active:scale-95">Resetar Tudo</button>
              <button onClick={() => setShowResetConfirm(false)} className="flex-1 bg-slate-700 hover:bg-slate-600 py-5 rounded-[1.5rem] font-black transition-all">Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {showUndoConfirm && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-800 p-10 rounded-[3rem] border border-white/10 max-sm w-full text-center">
            <h3 className="text-2xl font-black mb-8">Desfazer última ação?</h3>
            <div className="flex gap-4">
              <button onClick={handleUndo} className="flex-1 bg-red-600 py-4 rounded-2xl font-black active:scale-95 transition-all">Confirmar</button>
              <button onClick={() => setShowUndoConfirm(false)} className="flex-1 bg-slate-700 py-4 rounded-2xl font-black">Voltar</button>
            </div>
          </div>
        </div>
      )}

      {showTextInputModal.show && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-2xl z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-800 p-10 rounded-[3rem] border border-white/10 max-w-xl w-full">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-2xl font-black">Importar: {showTextInputModal.teamId === 'home' ? matchState.homeTeam.name : matchState.awayTeam.name}</h3>
              <button onClick={() => setShowTextInputModal({show: false, teamId: 'home'})} className="p-3 bg-slate-900 rounded-full"><X size={24} /></button>
            </div>
            <textarea className="w-full h-80 bg-slate-950 border border-white/5 rounded-[2rem] p-8 font-mono text-sm focus:ring-2 focus:ring-blue-500/50 outline-none resize-none text-blue-100 mb-8 shadow-inner" placeholder="Ex:&#10;1 Goleiro&#10;10 Atacante..." value={manualText} onChange={(e) => setManualText(e.target.value)} />
            <button onClick={handleManualTextInput} className="w-full bg-blue-600 hover:bg-blue-500 py-5 rounded-[1.5rem] font-black text-lg transition-all active:scale-95 shadow-xl">Carregar Jogadores</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  LayoutGrid, 
  List, 
  Mic, 
  Camera, 
  RotateCcw, 
  Play, 
  Pause,
  FileText,
  BarChart2,
  Trophy,
  ArrowRightLeft,
  Search,
  Type as TypeIcon,
  X,
  Edit2,
  Loader2,
  Target,
  AlertCircle,
  Flag,
  ChevronRight,
  Trash2,
  History,
  Plus,
  Minus
} from 'lucide-react';
import { 
  MatchState, 
  Player, 
  Team, 
  MatchEvent, 
  EventType, 
  Position,
  MatchPeriod
} from './types';
import { 
  DEFAULT_HOME_TEAM, 
  DEFAULT_AWAY_TEAM, 
  STORAGE_KEY 
} from './constants';
import Field from './components/Field';
import PlayerList from './components/PlayerList';
import MatchStats from './components/MatchStats';
import { parsePlayersFromImage, processVoiceCommand, generateMatchReport } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'main' | 'stats' | 'report'>('main');
  const [viewMode, setViewMode] = useState<'field' | 'list'>('field');
  const [matchState, setMatchState] = useState<MatchState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : {
      homeTeam: DEFAULT_HOME_TEAM,
      awayTeam: DEFAULT_AWAY_TEAM,
      events: [],
      startTime: null,
      currentTime: 0,
      isPaused: true,
      period: 'PRE_MATCH'
    };
  });

  const [history, setHistory] = useState<MatchState[]>([]);
  const [isRecording, setIsRecording] = useState(false);
  const [commandText, setCommandText] = useState('');
  const [finalReport, setFinalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [showUndoConfirm, setShowUndoConfirm] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [isProcessingImage, setIsProcessingImage] = useState<false | 'home' | 'away'>(false);

  const [showTextInputModal, setShowTextInputModal] = useState<{show: boolean, teamId: 'home' | 'away'}>({ show: false, teamId: 'home' });
  const [manualText, setManualText] = useState('');
  const [isEditingNames, setIsEditingNames] = useState<{home: boolean, away: boolean}>({ home: false, away: false });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(matchState));
  }, [matchState]);

  useEffect(() => {
    let interval: any;
    if (!matchState.isPaused && matchState.period !== 'FINISHED' && matchState.period !== 'INTERVAL') {
      interval = setInterval(() => {
        setMatchState(prev => ({
          ...prev,
          currentTime: prev.currentTime + 1
        }));
      }, 60000);
    }
    return () => clearInterval(interval);
  }, [matchState.isPaused, matchState.period]);

  const saveToHistory = useCallback(() => {
    setHistory(prev => [...prev.slice(-10), JSON.parse(JSON.stringify(matchState))]);
  }, [matchState]);

  const addEvent = (eventData: Omit<MatchEvent, 'id' | 'timestamp' | 'minute'>) => {
    saveToHistory();
    const newEvent: MatchEvent = {
      ...eventData,
      id: Math.random().toString(36).substr(2, 9),
      minute: matchState.currentTime,
      timestamp: Date.now(),
    };

    setMatchState(prev => {
      const updateTeam = (team: Team) => ({
        ...team,
        players: team.players.map(p => 
          p.id === newEvent.playerId || p.id === newEvent.relatedPlayerId
          ? { ...p, events: [...p.events, newEvent] }
          : p
        )
      });

      return {
        ...prev,
        events: [newEvent, ...prev.events],
        homeTeam: updateTeam(prev.homeTeam),
        awayTeam: updateTeam(prev.awayTeam),
      };
    });
  };

  const handleUndo = () => {
    if (history.length > 0) {
      setMatchState(history[history.length - 1]);
      setHistory(prev => prev.slice(0, -1));
      setShowUndoConfirm(false);
    }
  };

  const adjustScore = (teamId: 'home' | 'away', operation: 'add' | 'remove') => {
    if (operation === 'add') {
      const teamName = teamId === 'home' ? matchState.homeTeam.name : matchState.awayTeam.name;
      addEvent({
        type: 'GOAL',
        teamId,
        description: `Gol para ${teamName} (Ajuste Manual)`
      });
    } else {
      // Find the most recent goal for this team and remove it
      const goalIndex = matchState.events.findIndex(e => e.teamId === teamId && e.type === 'GOAL');
      if (goalIndex !== -1) {
        saveToHistory();
        setMatchState(prev => {
          const newEvents = [...prev.events];
          const removedEvent = newEvents.splice(goalIndex, 1)[0];

          // Also remove from player events if applicable
          const updateTeam = (team: Team) => ({
            ...team,
            players: team.players.map(p => 
              p.id === removedEvent.playerId 
              ? { ...p, events: p.events.filter(ev => ev.id !== removedEvent.id) }
              : p
            )
          });

          return {
            ...prev,
            events: newEvents,
            homeTeam: updateTeam(prev.homeTeam),
            awayTeam: updateTeam(prev.awayTeam),
          };
        });
      }
    }
  };

  const handleReset = () => {
    const newState: MatchState = {
      homeTeam: { ...DEFAULT_HOME_TEAM, players: [] },
      awayTeam: { ...DEFAULT_AWAY_TEAM, players: [] },
      events: [],
      startTime: null,
      currentTime: 0,
      isPaused: true,
      period: 'PRE_MATCH'
    };
    setMatchState(newState);
    setHistory([]);
    setFinalReport('');
    setShowResetConfirm(false);
  };

  const nextPeriod = () => {
    const periods: MatchPeriod[] = ['PRE_MATCH', '1T', 'INTERVAL', '2T', 'FINISHED'];
    const currentIndex = periods.indexOf(matchState.period);
    if (currentIndex < periods.length - 1) {
      const newPeriod = periods[currentIndex + 1];
      saveToHistory();
      setMatchState(prev => ({
        ...prev,
        period: newPeriod,
        isPaused: newPeriod === 'INTERVAL' || newPeriod === 'FINISHED' || newPeriod === 'PRE_MATCH'
      }));
      addEvent({
        type: 'PERIOD_START',
        teamId: 'none',
        description: `Início: ${newPeriod}`
      });
    }
  };

  const handleQuickAction = (type: EventType, teamId: 'home' | 'away') => {
    const team = matchState[teamId === 'home' ? 'homeTeam' : 'awayTeam'];
    addEvent({
      type,
      teamId,
      description: `${type.replace('_', ' ')} para ${team.name}`
    });
  };

  const handleCommand = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!commandText.trim()) return;

    try {
      const result = await processVoiceCommand(commandText, `Match minute ${matchState.currentTime}. Home: ${matchState.homeTeam.name}, Away: ${matchState.awayTeam.name}`);
      if (result.type !== 'INVALID') {
        const teamId = result.team === 'home' ? 'homeTeam' : 'awayTeam';
        const team = matchState[teamId];
        const player = team.players.find(p => p.number === result.playerNumber);
        addEvent({
          type: result.type as EventType,
          teamId: result.team as 'home' | 'away',
          playerId: player?.id,
          description: result.description
        });
        setCommandText('');
      } else {
        alert("Comando não reconhecido.");
      }
    } catch (error) { console.error(error); }
  };

  const getPositionCoordinates = (index: number, teamId: 'home' | 'away') => {
    const isHome = teamId === 'home';
    const baseRows = [
      { y: 50, x: isHome ? 8 : 92 }, // GK
      { y: 20, x: isHome ? 25 : 75 }, { y: 40, x: isHome ? 25 : 75 }, 
      { y: 60, x: isHome ? 25 : 75 }, { y: 80, x: isHome ? 25 : 75 }, // DF
      { y: 20, x: isHome ? 45 : 55 }, { y: 40, x: isHome ? 45 : 55 },
      { y: 60, x: isHome ? 45 : 55 }, { y: 80, x: isHome ? 45 : 55 }, // MF
      { y: 35, x: isHome ? 65 : 35 }, { y: 65, x: isHome ? 65 : 35 }, // FW
    ];
    return baseRows[index] || { y: 50, x: 50 };
  };

  const processPlayerList = (list: any[], teamId: 'home' | 'away') => {
    return list.map((p: any, i: number) => {
      const names = p.name.trim().split(' ');
      let shortName = names.length > 1 ? names[0] : p.name;
      const coords = getPositionCoordinates(i, teamId);
      return {
        id: Math.random().toString(36).substr(2, 9),
        fullName: p.name,
        name: shortName,
        number: p.number || (i + 1),
        teamId,
        isStarter: i < 11,
        position: (i === 0 ? 'GK' : i < 5 ? 'DF' : i < 9 ? 'MF' : 'FW') as Position,
        events: [],
        x: coords.x,
        y: coords.y
      } as Player;
    });
  };

  const handlePlayerMove = (teamId: 'home' | 'away', playerId: string, x: number, y: number) => {
    setMatchState(prev => {
      const targetTeamKey = teamId === 'home' ? 'homeTeam' : 'awayTeam';
      return {
        ...prev,
        [targetTeamKey]: {
          ...prev[targetTeamKey],
          players: prev[targetTeamKey].players.map(p => 
            p.id === playerId ? { ...p, x, y } : p
          )
        }
      };
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, teamId: 'home' | 'away') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingImage(teamId);
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result?.toString().split(',')[1];
      if (base64) {
        try {
          const data = await parsePlayersFromImage(base64);
          setMatchState(prev => ({
            ...prev,
            [teamId === 'home' ? 'homeTeam' : 'awayTeam']: { 
              ...prev[teamId === 'home' ? 'homeTeam' : 'awayTeam'], 
              name: data.teamName || prev[teamId === 'home' ? 'homeTeam' : 'awayTeam'].name,
              players: processPlayerList(data.players || [], teamId) 
            }
          }));
        } catch (error) { alert("Erro ao processar imagem."); } finally { setIsProcessingImage(false); e.target.value = ''; }
      }
    };
    reader.readAsDataURL(file);
  };

  const handleManualTextInput = () => {
    const lines = manualText.split('\n');
    const players = lines.filter(l => l.trim()).map(line => {
      const numMatch = line.match(/\d+/);
      const name = line.replace(/\d+/g, '').trim();
      return { name, number: numMatch ? parseInt(numMatch[0]) : 0 };
    });
    const teamKey = showTextInputModal.teamId === 'home' ? 'homeTeam' : 'awayTeam';
    setMatchState(prev => ({
      ...prev,
      [teamKey]: { ...prev[teamKey], players: processPlayerList(players, showTextInputModal.teamId) }
    }));
    setManualText('');
    setShowTextInputModal({ show: false, teamId: 'home' });
  };

  const getGoals = (teamId: 'home' | 'away') => 
    matchState.events.filter(e => e.teamId === teamId && e.type === 'GOAL').length;

  const createReport = async () => {
    if (matchState.events.length === 0) {
      setFinalReport("Nenhum lance registrado para gerar o relatório.");
      return;
    }
    setIsGeneratingReport(true);
    try {
      const eventsSummary = matchState.events
        .map(e => `[${e.minute}'] ${e.description}`)
        .reverse()
        .join('\n');

      const context = `Contexto: Partida entre ${matchState.homeTeam.name} e ${matchState.awayTeam.name}. Placar Final: ${getGoals('home')}x${getGoals('away')}.`;
      const report = await generateMatchReport(`${context}\n\nLances do jogo:\n${eventsSummary}`);
      setFinalReport(report);
    } catch (error) {
      setFinalReport("Erro ao gerar o relatório narrativo.");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col max-w-7xl mx-auto p-4 md:p-6 pb-32">
      {/* PREMIUM MATCH CONTROL BAR */}
      <div className="sticky top-4 z-[60] mb-8">
        <div className="bg-slate-900/95 border border-white/10 rounded-[2rem] shadow-[0_20px_50px_rgba(0,0,0,0.5)] backdrop-blur-2xl overflow-hidden ring-1 ring-white/5">
          <div className="flex flex-col md:flex-row items-stretch">
            {/* Left: Home Score & Controls */}
            <div className="flex-1 flex items-center justify-end px-6 py-4 bg-gradient-to-l from-transparent to-blue-500/5">
              <div className="text-right mr-6">
                <h3 className="text-white font-black text-lg uppercase tracking-tight truncate max-w-[150px]">{matchState.homeTeam.name}</h3>
                <div className="flex gap-1 justify-end mt-1">
                  {matchState.events.filter(e => e.teamId === 'home' && e.type === 'YELLOW_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-yellow-400 rounded-sm" />)}
                  {matchState.events.filter(e => e.teamId === 'home' && e.type === 'RED_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-red-500 rounded-sm" />)}
                </div>
              </div>
              <div className="flex flex-col items-center gap-1">
                <button 
                  onClick={() => adjustScore('home', 'add')} 
                  className="p-1 hover:bg-blue-500/20 rounded-md text-blue-400 transition-colors"
                >
                  <Plus size={16} />
                </button>
                <div className="text-5xl font-black tabular-nums text-white drop-shadow-lg leading-none">{getGoals('home')}</div>
                <button 
                  onClick={() => adjustScore('home', 'remove')} 
                  className="p-1 hover:bg-red-500/20 rounded-md text-red-400 transition-colors"
                >
                  <Minus size={16} />
                </button>
              </div>
            </div>

            {/* Center: Clock */}
            <div className="bg-slate-800/80 px-8 py-4 flex flex-col items-center justify-center border-x border-white/5 min-w-[240px]">
              <div className="flex items-center gap-2 mb-1">
                <span className="px-2 py-0.5 bg-blue-600 rounded-md text-[10px] font-black uppercase tracking-wider">{matchState.period}</span>
                <span className="text-slate-500 font-bold text-xs uppercase tracking-widest">Tempo Real</span>
              </div>
              <div className="text-5xl font-mono font-black tracking-tighter text-blue-400 drop-shadow-[0_0_10px_rgba(96,165,250,0.3)]">
                {matchState.currentTime < 10 ? `0${matchState.currentTime}` : matchState.currentTime}<span className="animate-pulse">:</span>00
              </div>
              <div className="flex items-center gap-3 mt-4">
                <button onClick={() => setMatchState(p => ({ ...p, isPaused: !p.isPaused, startTime: p.startTime || Date.now() }))} className={`p-3 rounded-2xl transition-all shadow-lg active:scale-95 flex items-center justify-center ${matchState.isPaused ? 'bg-emerald-500 hover:bg-emerald-400 text-white' : 'bg-red-500 hover:bg-red-400 text-white'}`}>
                  {matchState.isPaused ? <Play size={24} fill="currentColor" /> : <Pause size={24} fill="currentColor" />}
                </button>
                <button onClick={nextPeriod} className="p-3 bg-slate-700 hover:bg-slate-600 rounded-2xl text-slate-300 transition-all active:scale-95 group"><ChevronRight size={24} /></button>
                <button onClick={() => setShowResetConfirm(true)} className="p-3 bg-slate-700 hover:bg-red-900/40 rounded-2xl text-slate-400 hover:text-red-400 transition-all active:scale-95"><Trash2 size={24} /></button>
              </div>
            </div>

            {/* Right: Away Score & Controls */}
            <div className="flex-1 flex items-center justify-start px-6 py-4 bg-gradient-to-r from-transparent to-red-500/5">
              <div className="flex flex-col items-center gap-1">
                <button 
                  onClick={() => adjustScore('away', 'add')} 
                  className="p-1 hover:bg-blue-500/20 rounded-md text-blue-400 transition-colors"
                >
                  <Plus size={16} />
                </button>
                <div className="text-5xl font-black tabular-nums text-white drop-shadow-lg leading-none">{getGoals('away')}</div>
                <button 
                  onClick={() => adjustScore('away', 'remove')} 
                  className="p-1 hover:bg-red-500/20 rounded-md text-red-400 transition-colors"
                >
                  <Minus size={16} />
                </button>
              </div>
              <div className="text-left ml-6">
                <h3 className="text-white font-black text-lg uppercase tracking-tight truncate max-w-[150px]">{matchState.awayTeam.name}</h3>
                <div className="flex gap-1 justify-start mt-1">
                  {matchState.events.filter(e => e.teamId === 'away' && e.type === 'YELLOW_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-yellow-400 rounded-sm" />)}
                  {matchState.events.filter(e => e.teamId === 'away' && e.type === 'RED_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-red-500 rounded-sm" />)}
                </div>
              </div>
            </div>
          </div>

          <div className="bg-slate-950/50 border-t border-white/5 p-2 flex justify-between gap-1 overflow-x-auto no-scrollbar">
            <div className="flex gap-1">
              <button onClick={() => handleQuickAction('SHOT', 'home')} className="px-3 py-1.5 bg-slate-800 hover:bg-blue-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Chute</button>
              <button onClick={() => handleQuickAction('CORNER', 'home')} className="px-3 py-1.5 bg-slate-800 hover:bg-blue-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Escanteio</button>
              <button onClick={() => handleQuickAction('FOUL', 'home')} className="px-3 py-1.5 bg-slate-800 hover:bg-blue-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Falta</button>
            </div>
            <div className="flex gap-2">
               <button onClick={() => setShowUndoConfirm(true)} className="flex items-center gap-2 px-4 py-1.5 bg-slate-800 hover:bg-slate-700 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all"><RotateCcw size={12} /> Desfazer</button>
            </div>
            <div className="flex gap-1">
              <button onClick={() => handleQuickAction('FOUL', 'away')} className="px-3 py-1.5 bg-slate-800 hover:bg-red-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Falta</button>
              <button onClick={() => handleQuickAction('CORNER', 'away')} className="px-3 py-1.5 bg-slate-800 hover:bg-red-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Escanteio</button>
              <button onClick={() => handleQuickAction('SHOT', 'away')} className="px-3 py-1.5 bg-slate-800 hover:bg-red-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Chute</button>
            </div>
          </div>
        </div>
      </div>

      <nav className="flex gap-2 mb-8 bg-slate-900/50 p-1.5 rounded-2xl border border-slate-700 self-center shadow-inner">
        {(['main', 'stats', 'report'] as const).map((tab) => (
          <button key={tab} onClick={() => setActiveTab(tab)} className={`flex items-center gap-2 px-8 py-2.5 rounded-xl font-bold transition-all ${activeTab === tab ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-400 hover:text-white hover:bg-slate-800/40'}`}>
            {tab === 'main' ? 'Dashboard' : tab === 'stats' ? 'Dados' : 'Relatório'}
          </button>
        ))}
      </nav>

      <main className="flex-1 mb-8 overflow-hidden rounded-[2.5rem]">
        {activeTab === 'main' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full">
            <div className="lg:col-span-3 bg-slate-800/30 p-5 rounded-[2.5rem] border border-slate-700/50 flex flex-col gap-4 shadow-xl">
              <div className="flex items-center justify-between px-2">
                {isEditingNames.home ? (
                  <input autoFocus className="bg-slate-900 border border-blue-500 rounded-xl px-3 py-2 text-lg font-bold w-full" value={matchState.homeTeam.name} onBlur={() => setIsEditingNames(p => ({...p, home: false}))} onChange={(e) => setMatchState(p => ({...p, homeTeam: {...p.homeTeam, name: e.target.value}}))} />
                ) : (
                  <h2 className="text-xl font-black truncate flex items-center gap-2 group cursor-pointer" onClick={() => setIsEditingNames(p => ({...p, home: true}))}>{matchState.homeTeam.name} <Edit2 size={14} className="opacity-0 group-hover:opacity-100 transition-opacity" /></h2>
                )}
              </div>
              <PlayerList team={matchState.homeTeam} onPlayerClick={(p) => setCommandText(`Ação do jogador ${p.name}`)} />
              <div className="flex gap-2 mt-auto">
                <label className="flex-1 cursor-pointer flex items-center justify-center gap-2 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all"><Camera size={14} /> Foto <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'home')} /></label>
                <button onClick={() => setShowTextInputModal({ show: true, teamId: 'home' })} className="flex-1 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all">Texto</button>
              </div>
            </div>

            <div className="lg:col-span-6 flex flex-col gap-4">
              <div className="flex justify-center gap-2">
                <button onClick={() => setViewMode('field')} className={`px-6 py-2 rounded-xl font-bold transition-all ${viewMode === 'field' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}>Tático</button>
                <button onClick={() => setViewMode('list')} className={`px-6 py-2 rounded-xl font-bold transition-all ${viewMode === 'list' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}>Lista</button>
              </div>
              {viewMode === 'field' ? <Field homeTeam={matchState.homeTeam} awayTeam={matchState.awayTeam} onPlayerClick={(p) => setCommandText(`Ação do ${p.name}`)} onPlayerMove={handlePlayerMove} /> : 
              <div className="grid grid-cols-2 gap-4 h-[440px]"><PlayerList team={matchState.homeTeam} /><PlayerList team={matchState.awayTeam} /></div>}

              <div className="bg-slate-900/60 p-6 rounded-[2.5rem] border border-white/5 h-64 overflow-y-auto shadow-inner">
                <h4 className="text-[10px] font-black uppercase text-slate-500 mb-6 tracking-widest flex items-center gap-2"><History size={14} /> Histórico</h4>
                {matchState.events.length === 0 ? <p className="text-center text-slate-700 italic py-10">Aguardando lances...</p> : 
                matchState.events.map(e => (
                  <div key={e.id} className="flex gap-4 py-4 border-b border-white/5 last:border-0 items-start hover:bg-white/5 transition-colors px-4 rounded-xl">
                    <span className="font-mono text-blue-400 font-black text-xs pt-0.5">{e.minute}'</span>
                    <div className="flex flex-col"><span className="text-slate-200 font-bold text-sm">{e.description}</span><span className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">{e.type.replace('_', ' ')}</span></div>
                  </div>
                ))}
              </div>
            </div>

            <div className="lg:col-span-3 bg-slate-800/30 p-5 rounded-[2.5rem] border border-slate-700/50 flex flex-col gap-4 shadow-xl">
              <div className="flex items-center justify-between px-2 text-right">
                {isEditingNames.away ? (
                  <input autoFocus className="bg-slate-900 border border-red-500 rounded-xl px-3 py-2 text-lg font-bold w-full" value={matchState.awayTeam.name} onBlur={() => setIsEditingNames(p => ({...p, away: false}))} onChange={(e) => setMatchState(p => ({...p, awayTeam: {...p.awayTeam, name: e.target.value}}))} />
                ) : (
                  <h2 className="text-xl font-black truncate flex items-center justify-end gap-2 group cursor-pointer w-full" onClick={() => setIsEditingNames(p => ({...p, away: true}))}><Edit2 size={14} className="opacity-0 group-hover:opacity-100 transition-opacity" /> {matchState.awayTeam.name}</h2>
                )}
              </div>
              <PlayerList team={matchState.awayTeam} onPlayerClick={(p) => setCommandText(`Ação do jogador ${p.name}`)} />
              <div className="flex gap-2 mt-auto">
                <label className="flex-1 cursor-pointer flex items-center justify-center gap-2 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all"><Camera size={14} /> Foto <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'away')} /></label>
                <button onClick={() => setShowTextInputModal({ show: true, teamId: 'away' })} className="flex-1 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all">Texto</button>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'stats' && <MatchStats state={matchState} />}
        {activeTab === 'report' && (
          <div className="bg-slate-800/50 p-10 rounded-[3rem] border border-white/10 min-h-[60vh] flex flex-col shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-3xl font-black text-white">Relatório Narrativo</h2>
              <button onClick={createReport} disabled={isGeneratingReport} className="bg-blue-600 hover:bg-blue-500 px-10 py-4 rounded-2xl font-black flex items-center gap-3 transition-all active:scale-95">
                {isGeneratingReport ? <Loader2 size={24} className="animate-spin" /> : <FileText size={24} />} {isGeneratingReport ? 'Processando...' : 'Gerar Resumo IA'}
              </button>
            </div>
            <div className="flex-1 bg-slate-950/40 p-10 rounded-3xl border border-white/5 shadow-inner">
               {finalReport ? <div className="prose prose-invert max-w-none text-slate-300 text-lg leading-relaxed" dangerouslySetInnerHTML={{ __html: finalReport.replace(/\n/g, '<br/>') }} /> : 
               <div className="flex flex-col items-center justify-center h-full text-slate-600"><Trophy size={64} className="opacity-10 mb-6" /><p className="font-bold uppercase tracking-widest text-sm">Pronto para a narração final</p></div>}
            </div>
          </div>
        )}
      </main>

      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-full max-w-3xl px-4 z-[70]">
        <form onSubmit={handleCommand} className="bg-slate-900/90 p-3 rounded-full shadow-[0_30px_60px_rgba(0,0,0,0.8)] border border-white/10 flex items-center gap-3 backdrop-blur-3xl ring-8 ring-slate-900/40">
          <button type="button" onClick={() => setIsRecording(!isRecording)} className={`p-5 rounded-full transition-all active:scale-90 ${isRecording ? 'bg-red-600 animate-pulse' : 'bg-slate-800 hover:bg-slate-700'}`}>
            <Mic size={24} className="text-white" />
          </button>
          <div className="flex-1 relative">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-600" size={24} />
            <input type="text" placeholder="Descreva o lance... (ex: 'Cartão para o 10')" className="w-full bg-transparent py-4 pl-14 pr-6 font-bold text-xl placeholder:text-slate-600 text-white focus:outline-none" value={commandText} onChange={(e) => setCommandText(e.target.value)} />
          </div>
          <button type="submit" className="p-5 bg-blue-600 hover:bg-blue-500 rounded-full text-white font-black shadow-xl active:scale-90 transition-all"><ArrowRightLeft size={24} /></button>
        </form>
      </div>

      {showResetConfirm && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-800 p-12 rounded-[3rem] border border-white/10 max-w-md w-full text-center shadow-2xl">
            <div className="w-20 h-20 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-8 text-red-500"><Trash2 size={40} /></div>
            <h3 className="text-3xl font-black mb-4">Resetar Partida?</h3>
            <div className="flex gap-4">
              <button onClick={handleReset} className="flex-1 bg-red-600 hover:bg-red-500 py-5 rounded-[1.5rem] font-black transition-all active:scale-95">Resetar Tudo</button>
              <button onClick={() => setShowResetConfirm(false)} className="flex-1 bg-slate-700 hover:bg-slate-600 py-5 rounded-[1.5rem] font-black transition-all">Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {showUndoConfirm && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-800 p-10 rounded-[3rem] border border-white/10 max-sm w-full text-center">
            <h3 className="text-2xl font-black mb-8">Desfazer última ação?</h3>
            <div className="flex gap-4">
              <button onClick={handleUndo} className="flex-1 bg-red-600 py-4 rounded-2xl font-black active:scale-95 transition-all">Confirmar</button>
              <button onClick={() => setShowUndoConfirm(false)} className="flex-1 bg-slate-700 py-4 rounded-2xl font-black">Voltar</button>
            </div>
          </div>
        </div>
      )}

      {showTextInputModal.show && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-2xl z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-800 p-10 rounded-[3rem] border border-white/10 max-w-xl w-full">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-2xl font-black">Importar: {showTextInputModal.teamId === 'home' ? matchState.homeTeam.name : matchState.awayTeam.name}</h3>
              <button onClick={() => setShowTextInputModal({show: false, teamId: 'home'})} className="p-3 bg-slate-900 rounded-full"><X size={24} /></button>
            </div>
            <textarea className="w-full h-80 bg-slate-950 border border-white/5 rounded-[2rem] p-8 font-mono text-sm focus:ring-2 focus:ring-blue-500/50 outline-none resize-none text-blue-100 mb-8 shadow-inner" placeholder="Ex:&#10;1 Goleiro&#10;10 Atacante..." value={manualText} onChange={(e) => setManualText(e.target.value)} />
            <button onClick={handleManualTextInput} className="w-full bg-blue-600 hover:bg-blue-500 py-5 rounded-[1.5rem] font-black text-lg transition-all active:scale-95 shadow-xl">Carregar Jogadores</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { 
  LayoutGrid, 
  List, 
  Mic, 
  Camera, 
  RotateCcw, 
  Play, 
  Pause,
  FileText,
  BarChart2,
  Trophy,
  ArrowRightLeft,
  Search,
  Type as TypeIcon,
  X,
  Edit2,
  Loader2,
  Target,
  AlertCircle,
  Flag,
  ChevronRight,
  Trash2,
  History,
  Plus,
  Minus
} from 'lucide-react';
import { 
  MatchState, 
  Player, 
  Team, 
  MatchEvent, 
  EventType, 
  Position,
  MatchPeriod
} from './types';
import { 
  DEFAULT_HOME_TEAM, 
  DEFAULT_AWAY_TEAM, 
  STORAGE_KEY 
} from './constants';
import Field from './components/Field';
import PlayerList from './components/PlayerList';
import MatchStats from './components/MatchStats';
import { parsePlayersFromImage, processVoiceCommand, generateMatchReport } from './services/geminiService';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'main' | 'stats' | 'report'>('main');
  const [viewMode, setViewMode] = useState<'field' | 'list'>('field');
  const [matchState, setMatchState] = useState<MatchState>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : {
      homeTeam: DEFAULT_HOME_TEAM,
      awayTeam: DEFAULT_AWAY_TEAM,
      events: [],
      startTime: null,
      currentTime: 0,
      isPaused: true,
      period: 'PRE_MATCH'
    };
  });

  const [history, setHistory] = useState<MatchState[]>([]);
  const [isRecording, setIsRecording] = useState(false);
  const [commandText, setCommandText] = useState('');
  const [finalReport, setFinalReport] = useState<string>('');
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [showUndoConfirm, setShowUndoConfirm] = useState(false);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [isProcessingImage, setIsProcessingImage] = useState<false | 'home' | 'away'>(false);

  const [showTextInputModal, setShowTextInputModal] = useState<{show: boolean, teamId: 'home' | 'away'}>({ show: false, teamId: 'home' });
  const [manualText, setManualText] = useState('');
  const [isEditingNames, setIsEditingNames] = useState<{home: boolean, away: boolean}>({ home: false, away: false });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(matchState));
  }, [matchState]);

  useEffect(() => {
    let interval: any;
    if (!matchState.isPaused && matchState.period !== 'FINISHED' && matchState.period !== 'INTERVAL') {
      interval = setInterval(() => {
        setMatchState(prev => ({
          ...prev,
          currentTime: prev.currentTime + 1
        }));
      }, 60000);
    }
    return () => clearInterval(interval);
  }, [matchState.isPaused, matchState.period]);

  const saveToHistory = useCallback(() => {
    setHistory(prev => [...prev.slice(-10), JSON.parse(JSON.stringify(matchState))]);
  }, [matchState]);

  const addEvent = (eventData: Omit<MatchEvent, 'id' | 'timestamp' | 'minute'>) => {
    saveToHistory();
    const newEvent: MatchEvent = {
      ...eventData,
      id: Math.random().toString(36).substr(2, 9),
      minute: matchState.currentTime,
      timestamp: Date.now(),
    };

    setMatchState(prev => {
      const updateTeam = (team: Team) => ({
        ...team,
        players: team.players.map(p => 
          p.id === newEvent.playerId || p.id === newEvent.relatedPlayerId
          ? { ...p, events: [...p.events, newEvent] }
          : p
        )
      });

      return {
        ...prev,
        events: [newEvent, ...prev.events],
        homeTeam: updateTeam(prev.homeTeam),
        awayTeam: updateTeam(prev.awayTeam),
      };
    });
  };

  const handleUndo = () => {
    if (history.length > 0) {
      setMatchState(history[history.length - 1]);
      setHistory(prev => prev.slice(0, -1));
      setShowUndoConfirm(false);
    }
  };

  const adjustScore = (teamId: 'home' | 'away', operation: 'add' | 'remove') => {
    if (operation === 'add') {
      const teamName = teamId === 'home' ? matchState.homeTeam.name : matchState.awayTeam.name;
      addEvent({
        type: 'GOAL',
        teamId,
        description: `Gol para ${teamName} (Ajuste Manual)`
      });
    } else {
      const goalIndex = matchState.events.findIndex(e => e.teamId === teamId && e.type === 'GOAL');
      if (goalIndex !== -1) {
        saveToHistory();
        setMatchState(prev => {
          const newEvents = [...prev.events];
          const removedEvent = newEvents.splice(goalIndex, 1)[0];
          const updateTeam = (team: Team) => ({
            ...team,
            players: team.players.map(p => 
              p.id === removedEvent.playerId 
              ? { ...p, events: p.events.filter(ev => ev.id !== removedEvent.id) }
              : p
            )
          });
          return {
            ...prev,
            events: newEvents,
            homeTeam: updateTeam(prev.homeTeam),
            awayTeam: updateTeam(prev.awayTeam),
          };
        });
      }
    }
  };

  const handleReset = () => {
    const newState: MatchState = {
      homeTeam: { ...DEFAULT_HOME_TEAM, players: [] },
      awayTeam: { ...DEFAULT_AWAY_TEAM, players: [] },
      events: [],
      startTime: null,
      currentTime: 0,
      isPaused: true,
      period: 'PRE_MATCH'
    };
    setMatchState(newState);
    setHistory([]);
    setFinalReport('');
    setShowResetConfirm(false);
  };

  const nextPeriod = () => {
    const periods: MatchPeriod[] = ['PRE_MATCH', '1T', 'INTERVAL', '2T', 'FINISHED'];
    const currentIndex = periods.indexOf(matchState.period);
    if (currentIndex < periods.length - 1) {
      const newPeriod = periods[currentIndex + 1];
      saveToHistory();
      setMatchState(prev => ({
        ...prev,
        period: newPeriod,
        isPaused: newPeriod === 'INTERVAL' || newPeriod === 'FINISHED' || newPeriod === 'PRE_MATCH'
      }));
      addEvent({
        type: 'PERIOD_START',
        teamId: 'none',
        description: `Início: ${newPeriod}`
      });
    }
  };

  const handleQuickAction = (type: EventType, teamId: 'home' | 'away') => {
    const team = matchState[teamId === 'home' ? 'homeTeam' : 'awayTeam'];
    addEvent({
      type,
      teamId,
      description: `${type.replace('_', ' ')} para ${team.name}`
    });
  };

  const handleCommand = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!commandText.trim()) return;
    try {
      const result = await processVoiceCommand(commandText, `Match minute ${matchState.currentTime}. Home: ${matchState.homeTeam.name}, Away: ${matchState.awayTeam.name}`);
      if (result.type !== 'INVALID') {
        const teamId = result.team === 'home' ? 'homeTeam' : 'awayTeam';
        const team = matchState[teamId];
        const player = team.players.find(p => p.number === result.playerNumber);
        addEvent({
          type: result.type as EventType,
          teamId: result.team as 'home' | 'away',
          playerId: player?.id,
          description: result.description
        });
        setCommandText('');
      } else {
        alert("Comando não reconhecido.");
      }
    } catch (error) { console.error(error); }
  };

  const getPositionCoordinates = (index: number, teamId: 'home' | 'away') => {
    const isHome = teamId === 'home';
    const baseRows = [
      { y: 50, x: isHome ? 8 : 92 }, // GK
      { y: 20, x: isHome ? 25 : 75 }, { y: 40, x: isHome ? 25 : 75 }, 
      { y: 60, x: isHome ? 25 : 75 }, { y: 80, x: isHome ? 25 : 75 }, // DF
      { y: 20, x: isHome ? 45 : 55 }, { y: 40, x: isHome ? 45 : 55 },
      { y: 60, x: isHome ? 45 : 55 }, { y: 80, x: isHome ? 45 : 55 }, // MF
      { y: 35, x: isHome ? 65 : 35 }, { y: 65, x: isHome ? 65 : 35 }, // FW
    ];
    return baseRows[index] || { y: 50, x: 50 };
  };

  const processPlayerList = (list: any[], teamId: 'home' | 'away') => {
    return list.map((p: any, i: number) => {
      const names = p.name.trim().split(' ');
      let shortName = names.length > 1 ? names[0] : p.name;
      const coords = getPositionCoordinates(i, teamId);
      return {
        id: Math.random().toString(36).substr(2, 9),
        fullName: p.name,
        name: shortName,
        number: p.number || (i + 1),
        teamId,
        isStarter: i < 11,
        position: (i === 0 ? 'GK' : i < 5 ? 'DF' : i < 9 ? 'MF' : 'FW') as Position,
        events: [],
        x: coords.x,
        y: coords.y
      } as Player;
    });
  };

  const handlePlayerMove = (teamId: 'home' | 'away', playerId: string, x: number, y: number) => {
    setMatchState(prev => {
      const targetTeamKey = teamId === 'home' ? 'homeTeam' : 'awayTeam';
      return {
        ...prev,
        [targetTeamKey]: {
          ...prev[targetTeamKey],
          players: prev[targetTeamKey].players.map(p => 
            p.id === playerId ? { ...p, x, y } : p
          )
        }
      };
    });
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>, teamId: 'home' | 'away') => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessingImage(teamId);
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result?.toString().split(',')[1];
      if (base64) {
        try {
          const data = await parsePlayersFromImage(base64);
          setMatchState(prev => ({
            ...prev,
            [teamId === 'home' ? 'homeTeam' : 'awayTeam']: { 
              ...prev[teamId === 'home' ? 'homeTeam' : 'awayTeam'], 
              name: data.teamName || prev[teamId === 'home' ? 'homeTeam' : 'awayTeam'].name,
              players: processPlayerList(data.players || [], teamId) 
            }
          }));
        } catch (error) { alert("Erro ao processar imagem."); } finally { setIsProcessingImage(false); e.target.value = ''; }
      }
    };
    reader.readAsDataURL(file);
  };

  const handleManualTextInput = () => {
    const lines = manualText.split('\n');
    const players = lines.filter(l => l.trim()).map(line => {
      const numMatch = line.match(/\d+/);
      const name = line.replace(/\d+/g, '').trim();
      return { name, number: numMatch ? parseInt(numMatch[0]) : 0 };
    });
    const teamKey = showTextInputModal.teamId === 'home' ? 'homeTeam' : 'awayTeam';
    setMatchState(prev => ({
      ...prev,
      [teamKey]: { ...prev[teamKey], players: processPlayerList(players, showTextInputModal.teamId) }
    }));
    setManualText('');
    setShowTextInputModal({ show: false, teamId: 'home' });
  };

  const getGoals = (teamId: 'home' | 'away') => 
    matchState.events.filter(e => e.teamId === teamId && e.type === 'GOAL').length;

  const createReport = async () => {
    if (matchState.events.length === 0) {
      setFinalReport("Nenhum lance registrado para gerar o relatório.");
      return;
    }
    setIsGeneratingReport(true);
    try {
      const eventsSummary = matchState.events
        .map(e => `[${e.minute}'] ${e.description}`)
        .reverse()
        .join('\n');
      const context = `Contexto: Partida entre ${matchState.homeTeam.name} e ${matchState.awayTeam.name}. Placar Final: ${getGoals('home')}x${getGoals('away')}.`;
      const report = await generateMatchReport(`${context}\n\nLances do jogo:\n${eventsSummary}`);
      setFinalReport(report);
    } catch (error) { setFinalReport("Erro ao gerar o relatório narrativo."); } finally { setIsGeneratingReport(false); }
  };

  return (
    <div className="min-h-screen flex flex-col max-w-7xl mx-auto p-4 md:p-6 pb-32">
      {/* PREMIUM MATCH CONTROL BAR */}
      <div className="sticky top-4 z-[60] mb-8">
        <div className="bg-slate-900/95 border border-white/10 rounded-[2.5rem] shadow-[0_30px_60px_rgba(0,0,0,0.6)] backdrop-blur-3xl overflow-hidden ring-1 ring-white/5">
          <div className="flex flex-col md:flex-row items-stretch">

            {/* Left: Home Score & Team Controls */}
            <div className="flex-1 flex flex-col items-end justify-center px-8 py-6 bg-gradient-to-l from-transparent to-blue-500/5 border-r border-white/5">
              <div className="flex items-center gap-6 mb-4">
                <div className="text-right">
                  <h3 className="text-white font-black text-xl uppercase tracking-tight truncate max-w-[180px]">{matchState.homeTeam.name}</h3>
                  <div className="flex gap-1 justify-end mt-1">
                    {matchState.events.filter(e => e.teamId === 'home' && e.type === 'YELLOW_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-yellow-400 rounded-sm" />)}
                    {matchState.events.filter(e => e.teamId === 'home' && e.type === 'RED_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-red-500 rounded-sm" />)}
                  </div>
                </div>
                <div className="flex flex-col items-center gap-1">
                  <button onClick={() => adjustScore('home', 'add')} className="p-1 hover:bg-blue-500/20 rounded-md text-blue-400 transition-colors"><Plus size={18} /></button>
                  <div className="text-6xl font-black tabular-nums text-white drop-shadow-lg leading-none">{getGoals('home')}</div>
                  <button onClick={() => adjustScore('home', 'remove')} className="p-1 hover:bg-red-500/20 rounded-md text-red-400 transition-colors"><Minus size={18} /></button>
                </div>
              </div>
              {/* Quick Actions Home */}
              <div className="flex gap-1.5">
                <button onClick={() => handleQuickAction('SHOT', 'home')} className="px-3 py-1.5 bg-slate-800 hover:bg-blue-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Chute</button>
                <button onClick={() => handleQuickAction('CORNER', 'home')} className="px-3 py-1.5 bg-slate-800 hover:bg-blue-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Escanteio</button>
                <button onClick={() => handleQuickAction('FOUL', 'home')} className="px-3 py-1.5 bg-slate-800 hover:bg-blue-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Falta</button>
              </div>
            </div>

            {/* Center: Clock & Global Actions */}
            <div className="px-8 py-6 flex flex-col items-center justify-center min-w-[260px] bg-slate-900/50">
              <div className="flex items-center gap-2 mb-1">
                <span className="px-2 py-0.5 bg-blue-600 rounded-md text-[10px] font-black uppercase tracking-wider">{matchState.period}</span>
                <span className="text-slate-500 font-bold text-[10px] uppercase tracking-widest">Live Match</span>
              </div>
              <div className="text-5xl font-mono font-black tracking-tighter text-blue-400 drop-shadow-[0_0_15px_rgba(96,165,250,0.4)]">
                {matchState.currentTime < 10 ? `0${matchState.currentTime}` : matchState.currentTime}<span className="animate-pulse">:</span>00
              </div>
              <div className="flex items-center gap-3 mt-5">
                <button onClick={() => setMatchState(p => ({ ...p, isPaused: !p.isPaused, startTime: p.startTime || Date.now() }))} className={`p-4 rounded-2xl transition-all shadow-xl active:scale-90 flex items-center justify-center ${matchState.isPaused ? 'bg-emerald-500 hover:bg-emerald-400 text-white' : 'bg-red-500 hover:bg-red-400 text-white'}`}>
                  {matchState.isPaused ? <Play size={24} fill="currentColor" /> : <Pause size={24} fill="currentColor" />}
                </button>
                <button onClick={nextPeriod} className="p-3 bg-slate-800 hover:bg-slate-700 rounded-2xl text-slate-300 transition-all active:scale-95 group" title="Próximo Tempo"><ChevronRight size={24} /></button>
                <button onClick={() => setShowUndoConfirm(true)} className="p-3 bg-slate-800 hover:bg-slate-700 rounded-2xl text-slate-400 hover:text-white transition-all active:scale-95" title="Desfazer"><RotateCcw size={20} /></button>
                <button onClick={() => setShowResetConfirm(true)} className="p-3 bg-slate-800 hover:bg-red-900/40 rounded-2xl text-slate-500 hover:text-red-400 transition-all active:scale-95" title="Limpar Tudo"><Trash2 size={20} /></button>
              </div>
            </div>

            {/* Right: Away Score & Team Controls */}
            <div className="flex-1 flex flex-col items-start justify-center px-8 py-6 bg-gradient-to-r from-transparent to-red-500/5 border-l border-white/5">
              <div className="flex items-center gap-6 mb-4">
                <div className="flex flex-col items-center gap-1">
                  <button onClick={() => adjustScore('away', 'add')} className="p-1 hover:bg-blue-500/20 rounded-md text-blue-400 transition-colors"><Plus size={18} /></button>
                  <div className="text-6xl font-black tabular-nums text-white drop-shadow-lg leading-none">{getGoals('away')}</div>
                  <button onClick={() => adjustScore('away', 'remove')} className="p-1 hover:bg-red-500/20 rounded-md text-red-400 transition-colors"><Minus size={18} /></button>
                </div>
                <div className="text-left">
                  <h3 className="text-white font-black text-xl uppercase tracking-tight truncate max-w-[180px]">{matchState.awayTeam.name}</h3>
                  <div className="flex gap-1 justify-start mt-1">
                    {matchState.events.filter(e => e.teamId === 'away' && e.type === 'YELLOW_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-yellow-400 rounded-sm" />)}
                    {matchState.events.filter(e => e.teamId === 'away' && e.type === 'RED_CARD').map(e => <div key={e.id} className="w-1.5 h-3 bg-red-500 rounded-sm" />)}
                  </div>
                </div>
              </div>
              {/* Quick Actions Away */}
              <div className="flex gap-1.5">
                <button onClick={() => handleQuickAction('FOUL', 'away')} className="px-3 py-1.5 bg-slate-800 hover:bg-red-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Falta</button>
                <button onClick={() => handleQuickAction('CORNER', 'away')} className="px-3 py-1.5 bg-slate-800 hover:bg-red-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Escanteio</button>
                <button onClick={() => handleQuickAction('SHOT', 'away')} className="px-3 py-1.5 bg-slate-800 hover:bg-red-600 rounded-lg text-[10px] font-black uppercase text-slate-400 hover:text-white transition-all">Chute</button>
              </div>
            </div>

          </div>
        </div>
      </div>

      {/* TABS NAVIGATION */}
      <nav className="flex gap-2 mb-8 bg-slate-900/50 p-1.5 rounded-2xl border border-slate-700 self-center shadow-inner">
        {(['main', 'stats', 'report'] as const).map((tab) => (
          <button key={tab} onClick={() => setActiveTab(tab)} className={`flex items-center gap-2 px-8 py-2.5 rounded-xl font-bold transition-all ${activeTab === tab ? 'bg-slate-700 text-white shadow-lg' : 'text-slate-400 hover:text-white hover:bg-slate-800/40'}`}>
            {tab === 'main' ? 'Dashboard' : tab === 'stats' ? 'Dados' : 'Relatório'}
          </button>
        ))}
      </nav>

      <main className="flex-1 mb-8 overflow-hidden rounded-[2.5rem]">
        {activeTab === 'main' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full">
            <div className="lg:col-span-3 bg-slate-800/30 p-5 rounded-[2.5rem] border border-slate-700/50 flex flex-col gap-4 shadow-xl">
              <div className="flex items-center justify-between px-2">
                {isEditingNames.home ? (
                  <input autoFocus className="bg-slate-900 border border-blue-500 rounded-xl px-3 py-2 text-lg font-bold w-full" value={matchState.homeTeam.name} onBlur={() => setIsEditingNames(p => ({...p, home: false}))} onChange={(e) => setMatchState(p => ({...p, homeTeam: {...p.homeTeam, name: e.target.value}}))} />
                ) : (
                  <h2 className="text-xl font-black truncate flex items-center gap-2 group cursor-pointer" onClick={() => setIsEditingNames(p => ({...p, home: true}))}>{matchState.homeTeam.name} <Edit2 size={14} className="opacity-0 group-hover:opacity-100 transition-opacity" /></h2>
                )}
              </div>
              <PlayerList team={matchState.homeTeam} onPlayerClick={(p) => setCommandText(`Ação do jogador ${p.name}`)} />
              <div className="flex gap-2 mt-auto">
                <label className="flex-1 cursor-pointer flex items-center justify-center gap-2 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all"><Camera size={14} /> Foto <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'home')} /></label>
                <button onClick={() => setShowTextInputModal({ show: true, teamId: 'home' })} className="flex-1 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all">Texto</button>
              </div>
            </div>

            <div className="lg:col-span-6 flex flex-col gap-4">
              <div className="flex justify-center gap-2">
                <button onClick={() => setViewMode('field')} className={`px-6 py-2 rounded-xl font-bold transition-all ${viewMode === 'field' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}>Tático</button>
                <button onClick={() => setViewMode('list')} className={`px-6 py-2 rounded-xl font-bold transition-all ${viewMode === 'list' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500'}`}>Lista</button>
              </div>
              {viewMode === 'field' ? <Field homeTeam={matchState.homeTeam} awayTeam={matchState.awayTeam} onPlayerClick={(p) => setCommandText(`Ação do ${p.name}`)} onPlayerMove={handlePlayerMove} /> : 
              <div className="grid grid-cols-2 gap-4 h-[440px]"><PlayerList team={matchState.homeTeam} /><PlayerList team={matchState.awayTeam} /></div>}

              <div className="bg-slate-900/60 p-6 rounded-[2.5rem] border border-white/5 h-64 overflow-y-auto shadow-inner">
                <h4 className="text-[10px] font-black uppercase text-slate-500 mb-6 tracking-widest flex items-center gap-2"><History size={14} /> Histórico de Lances</h4>
                {matchState.events.length === 0 ? <p className="text-center text-slate-700 italic py-10">Aguardando lances...</p> : 
                matchState.events.map(e => (
                  <div key={e.id} className="flex gap-4 py-4 border-b border-white/5 last:border-0 items-start hover:bg-white/5 transition-colors px-4 rounded-xl">
                    <span className="font-mono text-blue-400 font-black text-xs pt-0.5">{e.minute}'</span>
                    <div className="flex flex-col"><span className="text-slate-200 font-bold text-sm">{e.description}</span><span className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">{e.type.replace('_', ' ')}</span></div>
                  </div>
                ))}
              </div>
            </div>

            <div className="lg:col-span-3 bg-slate-800/30 p-5 rounded-[2.5rem] border border-slate-700/50 flex flex-col gap-4 shadow-xl">
              <div className="flex items-center justify-between px-2 text-right">
                {isEditingNames.away ? (
                  <input autoFocus className="bg-slate-900 border border-red-500 rounded-xl px-3 py-2 text-lg font-bold w-full" value={matchState.awayTeam.name} onBlur={() => setIsEditingNames(p => ({...p, away: false}))} onChange={(e) => setMatchState(p => ({...p, awayTeam: {...p.awayTeam, name: e.target.value}}))} />
                ) : (
                  <h2 className="text-xl font-black truncate flex items-center justify-end gap-2 group cursor-pointer w-full" onClick={() => setIsEditingNames(p => ({...p, away: true}))}><Edit2 size={14} className="opacity-0 group-hover:opacity-100 transition-opacity" /> {matchState.awayTeam.name}</h2>
                )}
              </div>
              <PlayerList team={matchState.awayTeam} onPlayerClick={(p) => setCommandText(`Ação do jogador ${p.name}`)} />
              <div className="flex gap-2 mt-auto">
                <label className="flex-1 cursor-pointer flex items-center justify-center gap-2 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all"><Camera size={14} /> Foto <input type="file" className="hidden" accept="image/*" onChange={(e) => handleImageUpload(e, 'away')} /></label>
                <button onClick={() => setShowTextInputModal({ show: true, teamId: 'away' })} className="flex-1 p-4 bg-slate-700 hover:bg-slate-600 rounded-2xl text-xs font-bold transition-all">Texto</button>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'stats' && <MatchStats state={matchState} />}
        {activeTab === 'report' && (
          <div className="bg-slate-800/50 p-10 rounded-[3rem] border border-white/10 min-h-[60vh] flex flex-col shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h2 className="text-3xl font-black text-white">Relatório Narrativo</h2>
              <button onClick={createReport} disabled={isGeneratingReport} className="bg-blue-600 hover:bg-blue-500 px-10 py-4 rounded-2xl font-black flex items-center gap-3 transition-all active:scale-95">
                {isGeneratingReport ? <Loader2 size={24} className="animate-spin" /> : <FileText size={24} />} {isGeneratingReport ? 'Processando...' : 'Gerar Resumo IA'}
              </button>
            </div>
            <div className="flex-1 bg-slate-950/40 p-10 rounded-3xl border border-white/5 shadow-inner">
               {finalReport ? <div className="prose prose-invert max-w-none text-slate-300 text-lg leading-relaxed" dangerouslySetInnerHTML={{ __html: finalReport.replace(/\n/g, '<br/>') }} /> : 
               <div className="flex flex-col items-center justify-center h-full text-slate-600"><Trophy size={64} className="opacity-10 mb-6" /><p className="font-bold uppercase tracking-widest text-sm">Pronto para a narração final</p></div>}
            </div>
          </div>
        )}
      </main>

      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 w-full max-w-3xl px-4 z-[70]">
        <form onSubmit={handleCommand} className="bg-slate-900/90 p-3 rounded-full shadow-[0_30px_60px_rgba(0,0,0,0.8)] border border-white/10 flex items-center gap-3 backdrop-blur-3xl ring-8 ring-slate-900/40">
          <button type="button" onClick={() => setIsRecording(!isRecording)} className={`p-5 rounded-full transition-all active:scale-90 ${isRecording ? 'bg-red-600 animate-pulse' : 'bg-slate-800 hover:bg-slate-700'}`}>
            <Mic size={24} className="text-white" />
          </button>
          <div className="flex-1 relative">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-600" size={24} />
            <input type="text" placeholder="Descreva o lance... (ex: 'Cartão para o 10')" className="w-full bg-transparent py-4 pl-14 pr-6 font-bold text-xl placeholder:text-slate-600 text-white focus:outline-none" value={commandText} onChange={(e) => setCommandText(e.target.value)} />
          </div>
          <button type="submit" className="p-5 bg-blue-600 hover:bg-blue-500 rounded-full text-white font-black shadow-xl active:scale-90 transition-all"><ArrowRightLeft size={24} /></button>
        </form>
      </div>

      {showResetConfirm && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-800 p-12 rounded-[3rem] border border-white/10 max-w-md w-full text-center shadow-2xl">
            <div className="w-20 h-20 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-8 text-red-500"><Trash2 size={40} /></div>
            <h3 className="text-3xl font-black mb-4">Resetar Partida?</h3>
            <div className="flex gap-4">
              <button onClick={handleReset} className="flex-1 bg-red-600 hover:bg-red-500 py-5 rounded-[1.5rem] font-black transition-all active:scale-95">Resetar Tudo</button>
              <button onClick={() => setShowResetConfirm(false)} className="flex-1 bg-slate-700 hover:bg-slate-600 py-5 rounded-[1.5rem] font-black transition-all">Cancelar</button>
            </div>
          </div>
        </div>
      )}

      {showUndoConfirm && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-800 p-10 rounded-[3rem] border border-white/10 max-sm w-full text-center">
            <h3 className="text-2xl font-black mb-8">Desfazer última ação?</h3>
            <div className="flex gap-4">
              <button onClick={handleUndo} className="flex-1 bg-red-600 py-4 rounded-2xl font-black active:scale-95 transition-all">Confirmar</button>
              <button onClick={() => setShowUndoConfirm(false)} className="flex-1 bg-slate-700 py-4 rounded-2xl font-black">Voltar</button>
            </div>
          </div>
        </div>
      )}

      {showTextInputModal.show && (
        <div className="fixed inset-0 bg-black/95 backdrop-blur-2xl z-[100] flex items-center justify-center p-4">
          <div className="bg-slate-800 p-10 rounded-[3rem] border border-white/10 max-w-xl w-full">
            <div className="flex justify-between items-center mb-10">
              <h3 className="text-2xl font-black">Importar: {showTextInputModal.teamId === 'home' ? matchState.homeTeam.name : matchState.awayTeam.name}</h3>
              <button onClick={() => setShowTextInputModal({show: false, teamId: 'home'})} className="p-3 bg-slate-900 rounded-full"><X size={24} /></button>
            </div>
            <textarea className="w-full h-80 bg-slate-950 border border-white/5 rounded-[2rem] p-8 font-mono text-sm focus:ring-2 focus:ring-blue-500/50 outline-none resize-none text-blue-100 mb-8 shadow-inner" placeholder="Ex:&#10;1 Goleiro&#10;10 Atacante..." value={manualText} onChange={(e) => setManualText(e.target.value)} />
            <button onClick={handleManualTextInput} className="w-full bg-blue-600 hover:bg-blue-500 py-5 rounded-[1.5rem] font-black text-lg transition-all active:scale-95 shadow-xl">Carregar Jogadores</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
